  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "primary-vpc"
  }
}

# Secondary VPC to be associated with the zone
resource "aws_vpc" "secondary" {
  cidr_block = "10.1.0.0/16"

  tags = {
    Name = "secondary-vpc"
  }
}

# A Private Hosted Zone (initially associated with the primary VPC)
resource "aws_route53_zone" "private" {
  name = "example.internal"

  vpc {
    vpc_id = aws_vpc.primary.id
  }
}

# Route 53 Zone Association Resource
# Associates the secondary VPC with the existing Private Hosted Zone
resource "aws_route53_zone_association" "secondary_assoc" {
  zone_id = aws_route53_zone.private.id
  vpc_id  = aws_vpc.secondary.id
}

