terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Default provider for Route53 (Global service)
provider "aws" {
  region = "us-east-1"
}

# Provider for US West
provider "aws" {
  alias  = "us_west"
  region = "us-west-2"
}

# Provider for EU Central
provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1"
}

# ---------------------------------------------------------
# US West Resources
# ---------------------------------------------------------

# Find the latest solution stack for Python in US West
data "aws_elastic_beanstalk_solution_stack" "us_west" {
  provider    = aws.us_west
  most_recent = true
  name_regex  = "^64bit Amazon Linux 2023 v.*running Python"
}

resource "aws_elastic_beanstalk_application" "us_west" {
  provider = aws.us_west
  name     = "multi-region-app"
}

resource "aws_elastic_beanstalk_environment" "us_west" {
  provider              = aws.us_west
  name                  = "us_west"
  application           = aws_elastic_beanstalk_application.us_west.name
  solution_stack_name   = data.aws_elastic_beanstalk_solution_stack.us_west.name
  description           = "Environment in US West"

  setting {
    namespace = "aws:elasticbeanstalk:environment:tier"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }
}

# ---------------------------------------------------------
# EU Central Resources
# ---------------------------------------------------------

# Find the latest solution stack for Python in EU Central
data "aws_elastic_beanstalk_solution_stack" "eu_central" {
  provider    = aws.eu_central
  most_recent = true
  name_regex  = "^64bit Amazon Linux 2023 v.*running Python"
}

resource "aws_elastic_beanstalk_application" "eu_central" {
  provider = aws.eu_central
  name     = "multi-region-app"
}

resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider              = aws.eu_central
  name                  = "eu_central"
  application           = aws_elastic_beanstalk_application.eu_central.name
  solution_stack_name   = data.aws_elastic_beanstalk_solution_stack.eu_central.name
  description           = "Environment in EU Central"

  setting {
    namespace = "aws:elasticbeanstalk:environment:tier"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }
}

# ---------------------------------------------------------
# Route53 Resources (Latency-Based Routing)
# ---------------------------------------------------------

resource "aws_route53_zone" "main" {
  name = "example.com"
}

resource "aws_route53_record" "us_west" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.example.com"
  type    = "CNAME"
  ttl     = "60"
  records = [aws_elastic_beanstalk_environment.us_west.cname]

  latency_routing_policy {
    region = "us-west-2"
  }
}

resource "aws_route53_record" "eu_central" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.example.com"
  type    = "CNAME"
  ttl     = "60"
  records = [aws_elastic_beanstalk_environment.eu_central.cname]

  latency_routing_policy {
    region = "eu-central-1"
  }
}

