resource "aws_route53_record" "ptr_record" {
  zone_id = aws_route53_zone.reverse_zone.zone_id
  # The name corresponds to the last octet of the IP address in this reverse zone (e.g., 10.0.0.5)
  name    = "5"
  type    = "PTR"
  records = ["host.example53.com"]
  ttl     = 300
}

