# Data Sources for Default VPC
data "aws_vpc" "default_us" {
  provider = aws.us_east
  default  = true
}

data "aws_subnets" "default_us" {
  provider = aws.us_east
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default_us.id]
  }
}

# Security Groups
resource "aws_security_group" "eb_sg_us" {
  provider    = aws.us_east
  name_prefix = "eb-sg-us-"
  vpc_id      = data.aws_vpc.default_us.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "rds_sg_us" {
  provider    = aws.us_east
  name_prefix = "rds-sg-us-"
  vpc_id      = data.aws_vpc.default_us.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.eb_sg_us.id]
  }
}

# RDS Subnet Group
resource "aws_db_subnet_group" "rds_subnet_us" {
  provider       = aws.us_east
  name_prefix    = "rds-subnet-us-"
  subnet_ids     = data.aws_subnets.default_us.ids
  description    = "Subnet group for RDS in us-east-1"
}

# Database
resource "aws_db_instance" "main_db_us_east" {
  provider             = aws.us_east
  identifier           = "main_db_us_east"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  db_subnet_group_name = aws_db_subnet_group.rds_subnet_us.name
  vpc_security_group_ids = [aws_security_group.rds_sg_us.id]
  skip_final_snapshot  = true
  username             = "admin"
  password             = "changeme123"
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "myapp_us_east" {
  provider = aws.us_east
  name     = "myapp_us_east"
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "myenv_us_east" {
  provider   = aws.us_east
  name       = "myenv_us_east"
  application = aws_elastic_beanstalk_application.myapp_us_east.name

  solution_stack_name = "64bit Amazon Linux 2 v5.9.2 running Java 11"

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = data.aws_vpc.default_us.id
  }
  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", data.aws_subnets.default_us.ids)
  }
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile3.name
  }
  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/"
  }
  # Environment variables to connect to DB
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_HOSTNAME"
    value     = aws_db_instance.main_db_us_east.address
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_DB_NAME"
    value     = aws_db_instance.main_db_us_east.db_name
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_USERNAME"
    value     = aws_db_instance.main_db_us_east.username
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PASSWORD"
    value     = aws_db_instance.main_db_us_east.password
  }
}


# ==========================================
# EU-WEST-1 Configuration
# ==========================================

# Data Sources for Default VPC
data "aws_vpc" "default_eu" {
  provider = aws.eu_west
  default  = true
}

data "aws_subnets" "default_eu" {
