  name = "eb_ec2_profile"
  role = aws_iam_role.eb_role.name
}

# Shared RDS Database
resource "aws_db_subnet_group" "main" {
  name       = "main-db-subnet-group"
  subnet_ids = aws_subnet.public_subnets[*].id
}

resource "aws_db_instance" "myapp_db" {
  identifier             = "myapp_db"
  engine                 = "mysql"
  engine_version         = "5.7"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  skip_final_snapshot    = true
  publicly_accessible    = true
  username               = "admin"
  password               = "changeme123"
}

# EC2 Instances (Blue and Green Environments)
resource "aws_instance" "blue" {
  ami                    = data.aws_ami.amazon_linux.id
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.public_subnets[0].id
  vpc_security_group_ids = [aws_security_group.web_sg.id]
  iam_instance_profile   = aws_iam_instance_profile.eb_ec2_profile.name
  tags                   = { Name = "blue" }

  user_data = <<-EOF
              #!/bin/bash
              yum install -y httpd
              systemctl start httpd
              echo "<h1>Blue Environment</h1>" > /var/www/html/index.html
              EOF
}

resource "aws_instance" "green" {
  ami                    = data.aws_ami.amazon_linux.id
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.public_subnets[1].id
  vpc_security_group_ids = [aws_security_group.web_sg.id]
  iam_instance_profile   = aws_iam_instance_profile.eb_ec2_profile.name
  tags                   = { Name = "green" }

  user_data = <<-EOF
              #!/bin/bash
              yum install -y httpd
              systemctl start httpd
              echo "<h1>Green Environment</h1>" > /var/www/html/index.html
              EOF
}

# Route 53 Configuration
resource "aws_route53_zone" "main" {
  name = "myapp.example.com"
}

resource "aws_route53_health_check" "blue_health" {
  fqdn              = aws_instance.blue.public_ip
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  request_interval  = 30
  failure_threshold = 3
}

resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www"
  type    = "A"
  ttl     = "300"

  set_identifier = "blue-env"
  failover_routing_policy {
    type = "PRIMARY"
  }

  records        = [aws_instance.blue.public_ip]
  health_check_id = aws_route53_health_check.blue_health.id
}

resource "aws_route53_record" "secondary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www"
  type    = "A"
  ttl     = "300"

  set_identifier = "green-env"
  failover_routing_policy {
    type = "SECONDARY"
  }

  records = [aws_instance.green.public_ip]
}
