provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# IAM Resources
# -----------------------------------------------------------------------------

# IAM Role for Elastic Beanstalk EC2 Instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "elastic-beanstalk-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the Web Tier policy
resource "aws_iam_role_policy_attachment" "eb_web_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Attach the Worker Tier policy (Optional, depending on use case)
resource "aws_iam_role_policy_attachment" "eb_worker_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

# Instance Profile to be used by the environment
resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "elastic-beanstalk-instance-profile"
  role = aws_iam_role.eb_ec2_role.name
}

# -----------------------------------------------------------------------------
# Elastic Beanstalk Application
# -----------------------------------------------------------------------------

resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-eb-application"
  description = "My Elastic Beanstalk Application"
}

# -----------------------------------------------------------------------------
# Elastic Beanstalk Environment
# -----------------------------------------------------------------------------

resource "aws_elastic_beanstalk_environment" "env" {
  name                = "my-eb-environment"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.1.1 running Node.js 20"

  # Link the IAM Instance Profile created above
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }

  # Set Environment Type (LoadBalanced or SingleInstance)
  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  # Optional: Set health check URL
  setting {
    namespace = "aws:elasticbeanstalk:application"
    name      = "Application Healthcheck URL"
    value     = "/"
  }
}

