      name  = "EXAMPLE_VAR"
      value = "example-value"
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repo_url
    git_clone_depth = 1
    buildspec       = "buildspec.yml"

    auth {
      type     = "OAUTH"
      resource = aws_codebuild_source_credential.example.arn
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/example"
      status      = "ENABLED"
    }
  }
}

