    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetBucketAcl",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:PutObject"
        ]
        Resource = [
          "arn:aws:s3:::my-primary-artifacts-bucket",
          "arn:aws:s3:::my-primary-artifacts-bucket/*",
          "arn:aws:s3:::my-secondary-artifacts-bucket",
          "arn:aws:s3:::my-secondary-artifacts-bucket/*"
        ]
      }
    ]
  })
}

resource "aws_codebuild_project" "example" {
  name          = "example-project"
  description   = "Example CodeBuild project with secondary artifacts"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "5"

  artifacts {
    type     = "S3"
    location = "my-primary-artifacts-bucket"
    name     = "primary-artifact.zip"
    path     = "primary-artifacts"
    packaging = "ZIP"
  }

  secondary_artifacts {
    artifact_identifier = "secondary_artifact"
    type               = "S3"
    location           = "my-secondary-artifacts-bucket"
    name               = "secondary-artifact.zip"
    path               = "secondary-artifacts"
    packaging          = "ZIP"
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:5.0"
    type         = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
  }

  source {
    type            = "NO_SOURCE"
    buildspec       = <<EOF
version: 0.2

phases:
  build:
    commands:
      - echo "Build started on $(date)"
      - echo "Build completed successfully"
artifacts:
  files:
    - '**/*'
  secondary-artifacts:
    secondary_artifact:
      files:
        - '**/*'
EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name = "my-log-group"
      status     = "ENABLED"
    }
  }
}
