}

# CodeBuild Project with Batch Configuration
resource "aws_codebuild_project" "example" {
  name         = "example-batch-project"
  description  = "Example CodeBuild project with batch configuration"
  service_role = aws_iam_role.codebuild_role.arn

  # Set build type to BUILD_BATCH
  build_type = "BUILD_BATCH"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "EXAMPLE_VAR"
      value = "example-value"
    }
  }

  source {
    type      = "NO_SOURCE"
    buildspec = <<-EOF
      version: 0.2
      phases:
        build:
          commands:
            - echo "Running batch build..."
    EOF
  }

  # Build Batch Configuration
  build_batch_config {
    service_role = aws_iam_role.codebuild_role.arn

    # Define restrictions for the batch build
    restrictions {
      maximum_builds_allowed = 5
      compute_types_allowed = ["BUILD_GENERAL1_SMALL"]
    }

    # Combine artifacts from batch builds into a single location
    combine_artifacts = true

    # Set timeout for the batch
    timeout_in_mins = 30
  }
}

