      value = "production"
    }

    environment_variables {
      name  = "AWS_REGION"
      value = "us-east-1"
    }

    environment_variables {
      name  = "PARAMETER_STORE_VAR"
      value = "/myapp/config/db_url"
      type  = "PARAMETER_STORE"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "my-log-group"
      status      = "ENABLED"
