provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lex Bot to access CloudWatch Logs
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-v2-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_logs" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

# 2. Create the Lex V2 Bot
resource "aws_lexv2models_bot" "example_bot" {
  name                        = "ExampleTerraformBot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  type                        = "Bot"

  timeouts {
    create = "10m"
    delete = "10m"
  }
}

# 3. Create a Locale (US English)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                    = aws_lexv2models_bot.example_bot.id
  bot_version               = "DRAFT"
  locale_id                 = "en_US"
  nlu_confidence_threshold  = 0.40
}

# 4. Create a Simple Intent (HelloIntent)
resource "aws_lexv2models_intent" "hello_intent" {
  bot_id      = aws_lexv2models_bot.example_bot.id
  bot_version = "DRAFT"
  locale_id   = "en_US"
  name        = "HelloIntent"

  sample_utterances {
    utterance = "Hi"
  }
  sample_utterances {
    utterance = "Hello"
  }
  sample_utterances {
    utterance = "Hi there"
  }

  closing_setting {
    active = true
    response {
      message_group {
        message {
          plain_text_message {
            value = "Hello! How can I help you today?"
          }
        }
      }
    }
  }
}

# 5. Create a Draft Version
resource "aws_lexv2models_bot_version" "draft_version" {
  bot_id = aws_lexv2models_bot.example_bot.id
  locale_specification = {
    (aws_lexv2models_bot_locale.en_us.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  # Ensure the intent is created before creating the version snapshot
  depends_on = [
    aws_lexv2models_intent.hello_intent
  ]
}

# 6. Create an Alias (e.g., Production)
resource "aws_lexv2models_bot_alias" "production" {
  bot_id           = aws_lexv2models_bot.example_bot.id
  bot_alias_name   = "Production"
  bot_version      = aws_lexv2models_bot_version.draft_version.bot_version

  bot_alias_locale_settings {
    locale_id = aws_lexv2models_bot_locale.en_us.locale_id
    enabled   = true
  }
}

