  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexBotPolicy"
}

# -----------------------------------------------------------------------------
# Custom Slot Type
# -----------------------------------------------------------------------------
resource "aws_lex_slot_type" "pizza_size" {
  name        = "PizzaSize"
  value_selection_strategy = "ORIGINAL_VALUE"
  create_version = true

  enumeration_value {
    value = "Small"
  }
  enumeration_value {
    value = "Medium"
  }
  enumeration_value {
    value = "Large"
  }
}

# -----------------------------------------------------------------------------
# Slots
