resource "aws_lex_slot" "slot_size" {
  name            = "PizzaSizeSlot"
  slot_type       = aws_lex_slot_type.pizza_size.name
  value_selection_strategy = "ORIGINAL_VALUE"
  priority        = 1
}

resource "aws_lex_slot" "slot_crust" {
  name            = "PizzaCrustSlot"
  slot_type       = "AMAZON.AlphaNumeric" # Using built-in type for simplicity
  value_selection_strategy = "ORIGINAL_VALUE"
  priority        = 2
}

resource "aws_lex_slot" "slot_toppings" {
  name            = "PizzaToppingsSlot"
  slot_type       = "AMAZON.AlphaNumeric"
  value_selection_strategy = "ORIGINAL_VALUE"
  priority        = 3
}

# -----------------------------------------------------------------------------
# Intent
# -----------------------------------------------------------------------------
resource "aws_lex_intent" "order_pizza" {
  name           = "OrderPizzaIntent"
  create_version = true

  sample_utterances {
    utterance = "I want to order a pizza"
  }
  sample_utterances {
    utterance = "Order pizza"
  }
  sample_utterances {
    utterance = "Get me a {PizzaSizeSlot} pizza"
  }

  slot {
    name         = aws_lex_slot.slot_size.name
    slot_type    = aws_lex_slot_type.pizza_size.name
    priority     = 1
    value_elicitation_prompt {
      message {
        content      = "What size pizza would you like to order?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
  }

  slot {
    name         = aws_lex_slot.slot_crust.name
    slot_type    = "AMAZON.AlphaNumeric"
    priority     = 2
    value_elicitation_prompt {
      message {
        content      = "What type of crust would you like?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
  }

  slot {
    name         = aws_lex_slot.slot_toppings.name
    slot_type    = "AMAZON.AlphaNumeric"
    priority     = 3
    value_elicitation_prompt {
      message {
        content      = "What toppings would you like to add?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# -----------------------------------------------------------------------------
# Bot
# -----------------------------------------------------------------------------
resource "aws_lex_bot" "pizza_ordering_bot" {
  name           = "PizzaOrderingBot"
  child_directed = false
  locale         = "en-US"

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "$LATEST"
  }

  process_behavior = "BUILD"
  voice_id         = "Joanna"

  clarification_prompt {
    message {
      content      = "I'm sorry, I didn't understand that. Can you please repeat what size pizza you want?"
