terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# 1. IAM Role for the Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_attach" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexBotPolicy"
}

# 2. Create the Lex Bot (V2)
resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "PizzaOrderingBot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  type                        = "Bot"
}

# 3. Create the Initial Bot Version and Locale
resource "aws_lexv2models_bot_version" "initial_draft" {
  bot_id = aws_lexv2models_bot.pizza_bot.id
  locale_specification = {
    "en_US" = {
      bot_alias_locale_settings = {
        enabled = true
      }
    }
  }
}

resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                   = aws_lexv2models_bot.pizza_bot.id
  bot_version              = aws_lexv2models_bot_version.initial_draft.bot_version
  locale_id                = "en_US"
  nlu_confidence_threshold = 0.40
}

# 4. Create Custom Slot Types
resource "aws_lexv2models_slot_type" "pizza_size" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_version.initial_draft.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "PizzaSize"

  value_setting {
    resolution_strategy = "ORIGINAL_VALUE"
  }

  slot_type_values {
    sample_value {
      value = "Small"
    }
    synonyms {
      value = "S"
    }
    synonyms {
      value = "Personal"
    }
  }
  slot_type_values {
    sample_value {
      value = "Medium"
    }
    synonyms {
      value = "M"
    }
    synonyms {
      value = "Regular"
    }
  }
  slot_type_values {
    sample_value {
      value = "Large"
    }
    synonyms {
      value = "L"
    }
    synonyms {
      value = "Family"
    }
  }
}

resource "aws_lexv2models_slot_type" "pizza_topping" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_version.initial_draft.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "PizzaTopping"

  value_setting {
    resolution_strategy = "ORIGINAL_VALUE"
  }

  slot_type_values {
    sample_value { value = "Pepperoni" }
  }
  slot_type_values {
    sample_value { value = "Cheese" }
  }
  slot_type_values {
    sample_value { value = "Mushroom" }
  }
  slot_type_values {
    sample_value { value = "Veggie" }
  }
}

# 5. Create the Intent (OrderPizza)
resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_version.initial_draft.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterances {
    utterance = "I want to order a pizza"
  }
  sample_utterances {
    utterance = "Order pizza"
  }
  sample_utterances {
    utterance = "Get me a {PizzaTopping} pizza"
  }

  # Slot 1: Size
  slot {
    name         = "Size"
    description  = "The size of the pizza"
    slot_type_id = aws_lexv2models_slot_type.pizza_size.id
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        max_retries = 2
        message_groups {
          message {
            plain_text_message {
              value = "What size pizza would you like? We have Small, Medium, or Large."
            }
          }
        }
      }
    }
  }

  # Slot 2: Topping
  slot {
    name         = "Topping"
    description  = "The topping on the pizza"
    slot_type_id = aws_lexv2models_slot_type.pizza_topping.id
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        max_retries = 2
        message_groups {
          message {
            plain_text_message {
              value = "What topping would you like?"
            }
          }
        }
      }
    }
  }

  # Slot 3: Address (Follow-up question)
  slot {
    name         = "Address"
    description  = "The delivery address"
    slot_type_id = "AMAZON.Address" # Using built-in type
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        max_retries = 2
        message_groups {
          message {
            plain_text_message {
              value = "Where should we deliver your pizza? Please provide your address."
            }
          }
        }
      }
    }
  }

  # Closing Response
  closing_setting {
    active = true
    response_specification {
      message_groups {
        message {
          plain_text_message {
            value = "Got it! Ordering a {Size} {Topping} pizza for delivery to {Address}."
          }
        }
      }
    }
  }
}

