  }
  slot_type_values {
    sample_value {
      value = "Medium"
    }
    synonyms {
      value = "M"
    }
    synonyms {
      value = "Regular"
    }
  }
  slot_type_values {
    sample_value {
      value = "Large"
    }
    synonyms {
      value = "L"
    }
    synonyms {
      value = "Family"
    }
