# Intent: BookTrip
resource "aws_lex_intent" "book_trip" {
  name        = "BookTrip"
  description = "Intent to book a trip including car rental"

  # Sample utterances for the intent
  sample_utterances {
    utterances = ["I want to book a trip", "Book a trip", "I want to travel", "Plan a vacation"]
  }
  sample_utterances {
    utterances = ["I want to book a trip from {FromCity} to {ToCity}"]
  }

  # Conclusion action to be performed when the intent is fulfilled
  fulfillment_activity {
    type = "ReturnIntent"
  }

  # Rejection statement sent when the user does not provide a valid response
  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "I understand you would like to book a trip, but I can't perform that task. Would you like to book a car instead?"
    }
  }

  # Confirmation prompt sent before fulfilling the intent
  confirmation_prompt {
    message {
      content_type = "PlainText"
      content      = "Okay, I have you traveling from {FromCity} to {ToCity} on {DepartureDate} for {Duration} days with a {CarType} car. Is this correct?"
    }
    max_attempts = 2
  }

  # Closing statement sent when the intent is fulfilled
  statement {
    message {
      content_type = "PlainText"
      content      = "Your trip has been booked. Have a safe journey!"
    }
  }

  # Slot: FromCity
  slot {
    name             = "FromCity"
    description      = "The city the customer is departing from"
    slot_type        = aws_lex_slot_type.city.name
    slot_constraint  = "Required"
    priority         = 1
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "What city are you leaving from?"
      }
      max_attempts = 2
    }
  }

  # Slot: ToCity
  slot {
    name             = "ToCity"
    description      = "The city the customer is going to"
    slot_type        = aws_lex_slot_type.city.name
    slot_constraint  = "Required"
    priority         = 2
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "What city are you going to?"
      }
      max_attempts = 2
    }
  }

  # Slot: DepartureDate (Using Built-in Amazon Date type)
  slot {
    name             = "DepartureDate"
    description      = "The date the customer wants to leave"
    slot_type        = "AMAZON.Date"
    slot_constraint  = "Required"
    priority         = 3
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "What date do you want to leave?"
      }
      max_attempts = 2
    }
  }

  # Slot: Duration (Using Built-in Amazon Duration type)
  slot {
    name             = "Duration"
    description      = "The duration of the trip in days"
    slot_type        = "AMAZON.Duration"
    slot_constraint  = "Required"
    priority         = 4
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "How many days is the trip?"
      }
      max_attempts = 2
    }
  }

  # Slot: CarType
  slot {
    name             = "CarType"
    description      = "The type of car to rent"
    slot_type        = aws_lex_slot_type.car_type.name
    slot_constraint  = "Required"
    priority         = 5
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "What type of car would you like to rent?"
      }
      max_attempts = 2
    }
  }
}

# Bot: TripPlannerBot
resource "aws_lex_bot" "trip_planner" {
  child_directed = false
  name           = "TripPlannerBot"
  locale         = "en-US"

  # The behavior that Amazon Lex should use when the bot does not understand the user's intent
  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I could not understand your request. Please try again."
    }
  }

  # The prompt that Amazon Lex uses to confirm the user's intent
  clarification_prompt {
    message {
      content_type = "PlainText"
      content      = "I didn't understand you. Would you like to book a trip?"
    }
    max_attempts = 2
  }

  # The specific intent to attach to the bot
  intent {
    intent_name    = aws_lex_intent.book_trip.name
    intent_version = "$LATEST"
  }

  # Voice ID used for interaction
  voice_id        = "Joanna"

  # Process behavior determines if Amazon Lex builds the bot or not
  process_behavior = "BUILD"

  # Detect sentiment enabled
  detect_sentiment = true

  # Tags
  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}
```

