# Intent 2: OrderPizza (Main ordering intent with slots)
resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterances {
    utterance = "I want to order a pizza"
  }
  sample_utterances {
    utterance = "Order pizza"
  }
  sample_utterances {
    utterance = "Get me a {Size} pizza"
  }
  sample_utterances {
    utterance = "I'd like a {Size} pizza with {Topping}"
  }

  # Slot: Size
  slot {
    name = "Size"
    slot_type_id = "Amazon.String"
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What size pizza would you like? We have Small, Medium, or Large."
            }
          }
        }
        max_retries = 2
        allow_interrupt = true
      }
    }
  }

  # Slot: Topping
  slot {
    name = "Topping"
    slot_type_id = "Amazon.String"
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What toppings would you like? For example: Pepperoni, Mushrooms, or Cheese."
            }
          }
        }
        max_retries = 2
        allow_interrupt = true
      }
    }
  }

  # Slot: Quantity
  slot {
    name = "Quantity"
    slot_type_id = "Amazon.Number"
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "How many pizzas would you like to order?"
            }
          }
        }
        max_retries = 2
        allow_interrupt = true
      }
    }
  }

  closing_setting {
    active = true
    response {
      message_group {
        message {
          plain_text_message {
            value = "Got it. I have your order for {Quantity} {Size} pizza(s) with {Topping}. Is there anything else?"
          }
        }
      }
    }
  }
}

