  description        = "Intent to order a pizza for a kid"

  sample_utterances = [
    "I want a pizza",
    "Order pizza",
    "I'm hungry",
    "Can I have a {Size} {Topping} pizza",
    "Get me food",
    "I want {Topping}"
  ]

  slot {
    name               = "Size"
    slot_type          = aws_lex_slot_type.pizza_size.name
    slot_constraint    = "Required"
    priority           = 1
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "What size pizza do you want? You can pick Small, Medium, or Large."
      }
      max_attempts = 2
    }
  }

  slot {
    name               = "Topping"
    slot_type          = aws_lex_slot_type.pizza_topping.name
    slot_constraint    = "Required"
    priority           = 2
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "What topping do you like? We have Cheese, Pepperoni, Sausage, or Mushrooms."
      }
      max_attempts = 2
    }
  }

  fulfillment_activity {
    type = "ReturnMessage"
    messages {
      content_type = "PlainText"
      content      = "Yay! I ordered a {Size} {Topping} pizza just for you! It will be there soon."
    }
  }
}

resource "aws_lex_bot" "kids_pizza_bot" {
  child_directed = true
  name           = "KidsPizzaBot"
  locale         = "en-US"
  create_version = true
  process_behavior = "BUILD"
  idle_session_ttl_in_seconds = 300

  voice_id {
    voice_id = "Ivy" # Child voice
  }

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "I'm sorry, I couldn't understand. Do you want to try ordering a pizza again?"
    }
