provider "aws" {
  region = "us-east-1"
}

# --- IAM Role for Lex Bot ---
resource "aws_iam_role" "lex_bot_role" {
  name = "pizza-order-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexBotPolicy"
}

# --- Lambda Function ---
# Create a dummy Python file for the Lambda function
resource "local_file" "lambda_handler" {
  filename = "${path.module}/lambda_handler.py"
  content  = <<-EOT
    import json

    def lambda_handler(event, context):
        print("Event:", json.dumps(event))
        response = {
            "dialogAction": {
                "type": "Close",
                "fulfillmentState": "Fulfilled",
                "message": {
                    "contentType": "PlainText",
                    "content": "Your pizza order has been placed!"
                }
            }
        }
        return response
  EOT
}

# Zip the Python file
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_handler.filename
  output_path = "${path.module}/lambda_handler.zip"
}

# Create Lambda IAM Role
resource "aws_iam_role" "lambda_role" {
  name = "pizza-order-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Create Lambda Function
resource "aws_lambda_function" "pizza_order_fn" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "PizzaOrderFunction"
  role             = aws_iam_role.lambda_role.arn
  handler          = "lambda_handler.lambda_handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime          = "python3.9"

  depends_on = [
    local_file.lambda_handler
  ]
}

# Grant Lex permission to invoke the Lambda
resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order_fn.function_name
  principal     = "lex.amazonaws.com"
}

# --- Lex Slot Types ---

resource "aws_lex_slot_type" "pizza_size" {
  name        = "PizzaSize"
  value_selection_strategy = "ORIGINAL_VALUE"

  slot_type_value {
    name = "Small"
    synonyms {
      value = "Small"
    }
  }
  slot_type_value {
    name = "Medium"
    synonyms {
      value = "Medium"
    }
  }
  slot_type_value {
    name = "Large"
    synonyms {
      value = "Large"
    }
  }
}

resource "aws_lex_slot_type" "pizza_topping" {
  name        = "PizzaTopping"
  value_selection_strategy = "ORIGINAL_VALUE"

  slot_type_value {
    name = "Pepperoni"
  }
  slot_type_value {
    name = "Cheese"
  }
  slot_type_value {
    name = "Mushroom"
  }
}

# --- Lex Intent ---

resource "aws_lex_intent" "order_pizza" {
  name               = "OrderPizza"
  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri             = aws_lambda_function.pizza_order_fn.arn
      message_version = "1.0"
    }
  }

  sample_utterances = [
    "I want a pizza",
    "Order a {Size} pizza",
    "I want a {Size} pizza with {Topping}",
    "Order pizza"
  ]

  slot {
    name             = "Size"
    slot_type        = aws_lex_slot_type.pizza_size.name
    priority         = 1
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What size pizza would you like? Small, Medium, or Large?"
      }
    }
  }

  slot {
    name             = "Topping"
    slot_type        = aws_lex_slot_type.pizza_topping.name
    priority         = 2
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What topping would you like?"
      }
    }
  }
}

# --- Lex Bot ---

resource "aws_lex_bot" "pizza_bot" {
  child_directed = false
  name           = "PizzaOrderingBot"
  locale         = "en-US"
  role_arn       = aws_iam_role.lex_bot_role.arn
  voice_id       = "Joanna"
  idle_session_ttl_in_seconds = 300
  process_behavior = "BUILD"

  intent {
    intent_name = aws_lex_intent.order_pizza.name
    intent_version = "$LATEST"
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "I'm sorry, I didn't understand you. Would you like to order a pizza?"
    }
  }

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I could not understand your request."
    }
  }
}

# --- Lex Bot Version & Alias ---

resource "aws_lex_bot_version" "v1" {
  bot_name = aws_lex_bot.pizza_bot.name
  locale   = aws_lex_bot.pizza_bot.locale
}

resource "aws_lex_bot_alias" "prod" {
  bot_name    = aws_lex_bot.pizza_bot.name
  bot_version = aws_lex_bot_version.v1.version
  name        = "Production"
}

