provider "aws" {
  region = "us-east-1"
}

resource "aws_kinesis_stream" "example_stream" {
  name             = "example-input-stream"
  shard_count      = 1
  retention_period = 48
}

resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "analytics_policy" {
  name = "analytics-policy"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetRecord",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = aws_kinesis_stream.example_stream.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_kinesis_analytics_application" "example_app" {
  name = "example-analytics-application"

  inputs {
    name_prefix = "INPUT_STREAM"

    kinesis_stream_arn = aws_kinesis_stream.example_stream.arn
    kinesis_stream_name = aws_kinesis_stream.example_stream.name

    schema {
      record_encoding = "UTF-8"

      record_columns {
        name = "data"
        sql_type = "VARCHAR(256)"
      }
    }
  }
}
