```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Networking for Redshift
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "firehose-redshift-vpc"
  }
}

resource "aws_subnet" "main" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "firehose-redshift-subnet"
  }
}

resource "aws_security_group" "redshift_sg" {
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # In a real scenario, restrict this to Firehose service IPs or VPC endpoints
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-security-group"
  }
}

# 2. S3 Buckets (Required for Firehose Redshift destination)
# Bucket for the actual data delivery
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-redshift-delivery-bucket-example"
}

resource "aws_s3_bucket_ownership_controls" "firehose_bucket_ownership" {
  bucket = aws_s3_bucket.firehose_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_bucket_ownership]
  bucket     = aws_s3_bucket.firehose_bucket.id
  acl        = "private"
}

# Bucket for backups (Redshift destinations require backup mode to be enabled)
resource "aws_s3_bucket" "firehose_backup_bucket" {
  bucket = "firehose-redshift-backup-bucket-example"
}

resource "aws_s3_bucket_ownership_controls" "firehose_backup_bucket_ownership" {
  bucket = aws_s3_bucket.firehose_backup_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_backup_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_backup_bucket_ownership]
  bucket     = aws_s3_bucket.firehose_backup_bucket.id
  acl        = "private"
}

# 3. IAM Roles

# Role for Firehose to write to S3 and CloudWatch Logs
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*",
          aws_s3_bucket.firehose_backup_bucket.arn,
          "${aws_s3_bucket.firehose_backup_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["arn:aws:logs:*:*:*"]
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = "arn:aws:kinesis:*:*:stream/*" # If using Kinesis Data Streams as source
      },
      {
        Effect = "Allow"
        Action = [
          "redshift:DescribeClusters",
          "redshift:GetClusterCredentials"
        ]
        Resource = "*" # Restrict to specific cluster ARN in production
      }
    ]
  })
}

# Role for Redshift to read data from S3 (for COPY command)
resource "aws_iam_role" "redshift_role" {
  name = "redshift_s3_access_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "redshift_s3_policy" {
  name = "redshift_s3_policy"
  role = aws_iam_role.redshift_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      }
    ]
  })
}

# 4. Redshift Cluster
resource "aws_redshift_subnet_group" "main" {
  name       = "firehose-redshift-subnet-group"
  subnet_ids = [aws_subnet.main.id]

  tags = {
    Name = "Firehose Redshift Subnet Group"
  }
}

resource "random_password" "redshift_password" {
  length  = 16
  special = false
}

resource "aws_redshift_cluster" "main" {
  cluster_identifier = "firehose-redshift-cluster"
  database_name      = "firehose_db"
  master_username    = "admin"
  master_password    = random_password.redshift_password.result
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Networking
  cluster_subnet_group_name   = aws_redshift_subnet_group.main.name
  vpc_security_group_ids      = [aws_security_group.redshift_sg.id]
  publicly_accessible         = true # Required if Firehose is outside VPC or VPC endpoints not configured

  # IAM Roles for S3 Access (Copy command)
  iam_roles = [aws_iam_role.redshift_role.arn]

  skip_final_snapshot = true

  tags = {
    Environment = "test"
  }
}

# 5. Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_redshift_stream" {
  name        = "firehose-to-redshift-stream"
  destination = "redshift"

  # Redshift Configuration
  redshift_destination_configuration {
    cluster_jdbcurl = "jdbc:redshift://${aws_redshift_cluster.main.endpoint}/${aws_redshift_cluster.main.database_name}"
    username        = aws_redshift_cluster.main.master_username
    password        = aws_redshift_cluster.main.master_password
    role_arn        = aws_iam_role.firehose_role.arn

    # S3 Configuration for the intermediate data storage
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_bucket.arn
      prefix             = "data/"
      buffer_size        = 5
      buffer_interval    = 300
      compression_format = "UNCOMPRESSED"
    }

    # CloudWatch Logging Options
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/firehose/firehose-to-redshift-stream"
      log_stream_name = "S3Delivery"
    }

    # Redshift Copy Options
    copy_options = "DELIMITER ',' EMPTYASNULL BLANKSASNULL FILLRECORD TIMEFORMAT 'auto'"

    # Table Name in Redshift
    table_name = "firehose_target_table"

    # Data transformation (Optional)
    # processing_configuration { ... }

    # S3 Backup is Required for Redshift Destinations
    s3_backup_mode = "Enabled"
    s3_backup_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup_bucket.arn
      prefix             = "backup/"
      compression_format = "UNCOMPRESSED"
    }
  }

  tags = {
    Purpose = "Kinesis Firehose to Redshift"
  }
}

# Output the cluster endpoint for verification
output "redshift_endpoint" {
  value = aws_redshift_cluster.main.endpoint
}

output "firehose_stream_arn" {
  value = aws_kinesis_firehose_delivery_stream.extended_s3_redshift_stream.arn
}
```

