provider "aws" {
  region = "us-east-1"
}

# Data sources to construct ARNs dynamically
data "aws_region" "current" {}
data "aws_caller_identity" "current" {}

# 1. S3 Bucket (Required for Firehose buffering and backup)
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "my-firehose-opensearch-bucket"
}

resource "aws_s3_bucket_ownership_controls" "firehose_bucket_ownership" {
  bucket = aws_s3_bucket.firehose_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_bucket_ownership]
  bucket = aws_s3_bucket.firehose_bucket.id
  acl    = "private"
}

# 2. IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "kinesis_firehose_opensearch_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy Attachment for Firehose
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_opensearch_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPut",
          "es:ESHttpPost"
        ]
        Resource = "${aws_opensearch_domain.example.arn}/*"
      }
    ]
  })
}

# 4. OpenSearch Domain
resource "aws_opensearch_domain" "example" {
  domain_name    = "firehose-opensearch-domain"
  engine_type    = "OpenSearch"
  engine_version = "OpenSearch_1.3" # Ensure compatibility with your requirements

  cluster_config {
    instance_type          = "t3.small.search"
    instance_count         = 1
        dedicated_master_enabled = false
        zone_awareness_enabled   = false
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp2"
  }

  # Access Policy allowing the Firehose Role to write to the domain
  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "es:ESHttp*"
        ]
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.firehose_role.arn
        }
        Resource = "arn:aws:es:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:domain/${aws_opensearch_domain.example.domain_name}/*"
      }
    ]
  })
}

# 5. Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "example" {
  name        = "opensearch-delivery-stream"
  destination = "opensearch"

  # S3 Configuration (Mandatory for Firehose)
  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_bucket.arn
    buffer_size        = 5
    buffer_interval    = 300
    compression_format = "UNCOMPRESSED"
  }

  # OpenSearch Configuration
  opensearch_configuration {
    domain_arn     = aws_opensearch_domain.example.arn
    role_arn       = aws_iam_role.firehose_role.arn
    index_name     = "firehose-index"
    type_name      = "_doc" # Standard for OpenSearch 7.x+
    s3_backup_mode = "FailedDocumentsOnly"

    # S3 Backup Configuration for failed OpenSearch documents
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_bucket.arn
      prefix             = "opensearch-failed/"
      buffer_size        = 5
      buffer_interval    = 300
    }

    # Processing configuration (Optional)
    # cloudwatch_logging_options {
    #   enabled = true
    #   log_group_name = aws_cloudwatch_log_group.firehose_log.name
    #   log_stream_name = "S3Delivery"
    # }
  }
}
```

