  })
}

# IAM Policy attached to the Firehose Role
resource "aws_iam_role_policy" "firehose_policy" {
  name = "kinesis-firehose-splunk-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
