          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.backup.arn,
          "${aws_s3_bucket.backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "aoss:BatchGetDocuments",
          "aoss:CreateIndex",
          "aoss:DeleteIndex",
          "aoss:UpdateIndex",
          "aoss:ReadDocument",
          "aoss:WriteDocument",
          "aoss:APIAccessAll"
        ]
        Resource = "arn:aws:aoss:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:collection/${aws_opensearchserverless_collection.this.id}"
      }
    ]
  })
}

# --- OpenSearch Serverless Collection ---
data "aws_region" "current" {}
data "aws_caller_identity" "current" {}

resource "aws_opensearchserverless_collection" "this" {
  name = "${random_pet.this.id}-collection"
  type = "SEARCH"
}

# Network Security Policy (Public Access)
resource "aws_opensearchserverless_security_policy" "network" {
  name        = "${random_pet.this.id}-network-policy"
  type        = "network"
  description = "Network policy for the collection"

  policy = jsonencode([
    {
      Rules = [
        {
          ResourceType = "collection",
          Resource     = [
            "collection/${aws_opensearchserverless_collection.this.id}"
          ]
        }
      ],
      AllowFromPublic = true
    }
  ])
}

# Data Access Policy
resource "aws_opensearchserverless_access_policy" "data" {
  name        = "${random_pet.this.id}-data-access-policy"
  type        = "data"
  description = "Data access policy for Firehose"

  policy = jsonencode([
    {
      Rules = [
        {
          ResourceType = "index",
          Resource     = [
            "index/${aws_opensearchserverless_collection.this.id}/*"
          ],
          Permission = [
            "aoss:CreateIndex",
            "aoss:DeleteIndex",
            "aoss:UpdateIndex",
            "aoss:ReadDocument",
            "aoss:WriteDocument"
          ]
        }
      ],
      Principal = [
        aws_iam_role.firehose_role.arn
      ]
    }
  ])
}

# --- Kinesis Firehose Delivery Stream ---
resource "aws_kinesis_firehose_delivery_stream" "this" {
  name        = "${random_pet.this.id}-delivery-stream"
  destination = "opensearchserverless"

  opensearchserverless_configuration {
    collection_arn       = aws_opensearchserverless_collection.this.arn
    data_access_role_arn = aws_iam_role.firehose_role.arn
    index_name           = "firehose-index"

    buffering_interval   = 300
    buffering_size       = 5
    retry_duration       = 60
  }

  s3_configuration {
    bucket_arn        = aws_s3_bucket.backup.arn
    role_arn          = aws_iam_role.firehose_role.arn
    buffer_size       = 5
    buffer_interval   = 300
    compression_format = "UNCOMPRESSED"
  }

  server_side_encryption {
    enabled = true
  }

  # Configuration for backing up failed records
  s3_backup_mode = "FailedDocumentsOnly"
}
