terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# Variables
# -----------------------------------------------------------------------------
variable "http_endpoint_url" {
  description = "The URL of the HTTP Endpoint (e.g., New Relic Log API)"
  type        = string
  # Example for New Relic: https://log-api.newrelic.com/log/v1
  default     = "https://http-endpoint.example.com/ingest"
}

variable "http_endpoint_access_key" {
  description = "The access key required for the HTTP Endpoint (e.g., New Relic License Key)"
  type        = string
  sensitive   = true
}

variable "s3_backup_bucket_name" {
  description = "The name of the S3 bucket to use for backup"
  type        = string
  default     = "firehose-http-backup-bucket"
}

# -----------------------------------------------------------------------------
# S3 Bucket for Backup
# -----------------------------------------------------------------------------
resource "aws_s3_bucket" "backup_bucket" {
  bucket = var.s3_backup_bucket_name
}

resource "aws_s3_bucket_versioning" "backup_bucket" {
  bucket = aws_s3_bucket.backup_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_ownership_controls" "backup_bucket" {
  bucket = aws_s3_bucket.backup_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "backup_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.backup_bucket]
  bucket     = aws_s3_bucket.backup_bucket.id
  acl        = "private"
}

# -----------------------------------------------------------------------------
# CloudWatch Logs for Firehose
# -----------------------------------------------------------------------------
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name              = "/aws/kinesisfirehose/http-stream"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "firehose_log_stream" {
  name           = "S3Delivery"
  log_group_name = aws_cloudwatch_log_group.firehose_log_group.name
}

# -----------------------------------------------------------------------------
# IAM Role for Firehose
# -----------------------------------------------------------------------------
resource "aws_iam_role" "firehose_role" {
  name = "firehose-http-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-http-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.backup_bucket.arn,
          "${aws_s3_bucket.backup_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:*:*:*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Decrypt"
        ]
        Resource = "*" # Restrict to specific KMS key if used
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# Kinesis Firehose Delivery Stream
# -----------------------------------------------------------------------------
resource "aws_kinesis_firehose_delivery_stream" "http_stream" {
  name        = "http-endpoint-stream"
  destination = "http_endpoint"

  # HTTP Endpoint Configuration
  http_endpoint_configuration {
    url        = var.http_endpoint_url
    name       = "NewRelicEndpoint"
    access_key = var.http_endpoint_access_key

    # S3 Backup Configuration (Required for HTTP Endpoints)
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.backup_bucket.arn
      prefix             = "backups/http/"
      error_output_prefix = "errors/http/"
      buffering_size     = 5
      buffering_interval = 300
    }
  }

  # CloudWatch Logging Configuration
  server_side_encryption {
    enabled = true
  }

  cloudwatch_logging_options {
    enabled         = true
    log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
    log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
  }
}

