# OpenSearch Domain
resource "aws_opensearch_domain" "domain" {
  name = "firehose-opensearch-domain"

  engine_version = "OpenSearch_1.0"

  # VPC Configuration
  vpc_options {
    subnet_ids = [
      aws_subnet.private_1.id,
      aws_subnet.private_2.id
    ]
    security_group_ids = [aws_security_group.opensearch_sg.id]
  }

  cluster_config {
    instance_type  = "t3.small.search"
    instance_count = 2
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp2"
  }

  # Access policy to allow the Firehose Role to write
  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "es:ESHttp*"
        ]
        Effect   = "Allow"
        Principal = {
          AWS = aws_iam_role.firehose_role.arn
        }
        Resource = "${aws_opensearch_domain.domain.arn}/*"
      }
    ]
  })
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "firehose-to-opensearch"
  destination = "opensearch"

  opensearch_configuration {
    domain_arn = aws_opensearch_domain.domain.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "firehose-index"
    # Use the VPC endpoint of the OpenSearch domain
    cluster_endpoint = aws_opensearch_domain.domain.endpoint

    s3_backup_mode = "AllDocuments"

    s3_configuration {
      bucket_arn = aws_s3_bucket.backup_bucket.arn
      role_arn   = aws_iam_role.firehose_role.arn
      buffer_size = 5
      buffer_interval = 300
    }

    # CloudWatch logging for the stream
    cloudwatch_logging_options {
      enabled = true
      log_group_name = aws_cloudwatch_log_group.firehose.name
      log_stream_name = aws_cloudwatch_log_stream.firehose.name
    }

    processing_configuration {
      enabled = true

      processors {
        type = "Lambda"

        parameters {
          parameter_name  = "LambdaArn"
          parameter_value = aws_lambda_function.processor.arn
        }

        parameters {
          parameter_name  = "BufferSizeInMBs"
          parameter_value = 3
        }

        parameters {
          parameter_name  = "BufferIntervalInSeconds"
          parameter_value = 60
        }
      }
    }
  }
}

# CloudWatch Log Group for Firehose
resource "aws_cloudwatch_log_group" "firehose" {
  name              = "/aws/firehose/firehose-to-opensearch"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "firehose" {
  name           = "FirehoseStream"
  log_group_name = aws_cloudwatch_log_group.firehose.name
}

# Lambda Processor (Optional placeholder for Processing Configuration)
