```hcl
provider "aws" {
  region = "us-east-1"
}

# VPC and Networking
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "firehose-vpc"
  }
}

resource "aws_subnet" "private_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "${data.aws_region.current.name}a"

  tags = {
    Name = "firehose-subnet-1"
  }
}

resource "aws_subnet" "private_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "${data.aws_region.current.name}b"

  tags = {
    Name = "firehose-subnet-2"
  }
}

data "aws_region" "current" {}

# Security Group for OpenSearch
resource "aws_security_group" "opensearch_sg" {
  name        = "opensearch-sg"
  description = "Allow traffic for OpenSearch"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block] # Firehose needs to reach the domain
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# S3 Bucket for Backup (Required for Firehose OpenSearch Destination)
resource "aws_s3_bucket" "backup_bucket" {
  bucket = "firehose-opensearch-backup-bucket-12345"
}

resource "aws_s3_bucket_ownership_controls" "backup_bucket_ownership" {
  bucket = aws_s3_bucket.backup_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "backup_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.backup_bucket_ownership]
  bucket     = aws_s3_bucket.backup_bucket.id
  acl        = "private"
}

# IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose-opensearch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.backup_bucket.arn,
          "${aws_s3_bucket.backup_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpDelete",
          "es:ESHttpGet",
          "es:ESHttpHead",
          "es:ESHttpPut",
          "es:ESHttpPost",
          "es:DescribeDomain",
          "es:DescribeDomains"
        ]
        Resource = [
          "${aws_opensearch_domain.domain.arn}/*",
          aws_opensearch_domain.domain.arn
        ]
      }
    ]
  })
}

# OpenSearch Domain
resource "aws_opensearch_domain" "domain" {
  name = "firehose-opensearch-domain"

  engine_version = "OpenSearch_1.0"

  # VPC Configuration
  vpc_options {
    subnet_ids = [
      aws_subnet.private_1.id,
      aws_subnet.private_2.id
    ]
    security_group_ids = [aws_security_group.opensearch_sg.id]
  }

  cluster_config {
    instance_type  = "t3.small.search"
    instance_count = 2
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp2"
  }

  # Access policy to allow the Firehose Role to write
  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "es:ESHttp*"
        ]
        Effect   = "Allow"
        Principal = {
          AWS = aws_iam_role.firehose_role.arn
        }
        Resource = "${aws_opensearch_domain.domain.arn}/*"
      }
    ]
  })
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "firehose-to-opensearch"
  destination = "opensearch"

  opensearch_configuration {
    domain_arn = aws_opensearch_domain.domain.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "firehose-index"
    # Use the VPC endpoint of the OpenSearch domain
    cluster_endpoint = aws_opensearch_domain.domain.endpoint

    s3_backup_mode = "AllDocuments"

    s3_configuration {
      bucket_arn = aws_s3_bucket.backup_bucket.arn
      role_arn   = aws_iam_role.firehose_role.arn
      buffer_size = 5
      buffer_interval = 300
    }

    # CloudWatch logging for the stream
    cloudwatch_logging_options {
      enabled = true
      log_group_name = aws_cloudwatch_log_group.firehose.name
      log_stream_name = aws_cloudwatch_log_stream.firehose.name
    }

    processing_configuration {
      enabled = true

      processors {
        type = "Lambda"

        parameters {
          parameter_name  = "LambdaArn"
          parameter_value = aws_lambda_function.processor.arn
        }

        parameters {
          parameter_name  = "BufferSizeInMBs"
          parameter_value = 3
        }

        parameters {
          parameter_name  = "BufferIntervalInSeconds"
          parameter_value = 60
        }
      }
    }
  }
}

# CloudWatch Log Group for Firehose
resource "aws_cloudwatch_log_group" "firehose" {
  name              = "/aws/firehose/firehose-to-opensearch"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "firehose" {
  name           = "FirehoseStream"
  log_group_name = aws_cloudwatch_log_group.firehose.name
}

# Lambda Processor (Optional placeholder for Processing Configuration)
resource "aws_lambda_function" "processor" {
  filename         = "processor.zip"
  function_name    = "firehose_processor"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  source_code_hash = filebase64sha256("processor.zip")
  runtime          = "python3.9"
}

# Dummy zip file for lambda to prevent errors if not present
resource "null_resource" "create_lambda_zip" {
  provisioner "local-exec" {
    command = "echo 'def handler(event, context): return event' > index.py && zip processor.zip index.py"
  }
}
data "aws_iam_policy_document" "lambda_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["lambda.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}
resource "aws_iam_role" "lambda_role" {
  name               = "firehose-lambda-role"
  assume_role_policy = data.aws_iam_policy_document.lambda_assume_role.json
}
