provider "aws" {
  region = "us-east-1"
}

# IAM Role for the Kinesis Analytics Application
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a policy granting permissions to read from Kinesis and write to CloudWatch
resource "aws_iam_role_policy_attachment" "kinesis_analytics_attach" {
  role       = aws_iam_role.kinesis_analytics_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisAnalyticsFullAccess"
}

# Kinesis Stream (Source)
resource "aws_kinesis_stream" "input_stream" {
  name        = "example-input-stream"
  shard_count = 1
}

# CloudWatch Log Group for Application Logs
resource "aws_cloudwatch_log_group" "analytics_log_group" {
  name              = "/aws/kinesis-analytics/example-sql-app"
  retention_in_days = 7
}

# CloudWatch Log Stream
