# Variable for the Kendra Index ID
variable "kendra_index_id" {
  description = "The ID of the Kendra index"
  type        = string
}

# Variable for the IAM Role ARN
variable "kendra_role_arn" {
  description = "The ARN of the IAM role that grants Kendra permission to access the data source"
  type        = string
}

resource "aws_kendra_data_source" "web_crawler" {
  name        = "example-web-crawler"
  index_id    = var.kendra_index_id
  role_arn    = var.kendra_role_arn
  type        = "WEBCRAWLER"
  description = "Web Crawler data source with URL inclusion and exclusion patterns"

  configuration {
    web_crawler_configuration {
      # Seed URLs are required for a web crawler to start
      url_configuration {
        seed_url_configuration {
          seed_urls = ["https://example.com"]
        }
      }

      # URL Inclusion Patterns: Only crawl URLs that match these regular expressions
      url_inclusion_patterns = [
        "https://example.com/public/.*",
        "https://example.com/products/.*"
      ]

      # URL Exclusion Patterns: Do not crawl URLs that match these regular expressions
      url_exclusion_patterns = [
        "https://example.com/private/.*",
        "https://example.com/admin/.*",
        ".*\.pdf$"
      ]
    }
  }
}

