}

provider "aws" {
  region = "us-east-1"
}

# IAM Role required by Kendra to access resources and write logs
resource "aws_iam_role" "kendra_role" {
  name = "kendra-basic-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the full access policy for simplicity in this basic example
resource "aws_iam_role_policy_attachment" "kendra_attach" {
  role       = aws_iam_role.kendra_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKendraFullAccess"
}

resource "aws_kendra_index" "example" {
  name     = "basic-kendra-index"
  role_arn = aws_iam_role.kendra_role.arn
  edition  = "DEVELOPER_EDITION"

  # Note: Default Document Metadata Configuration Updates (system fields like 
  # _created_at, _last_updated_at, _source_uri, etc.) are applied automatically 
  # by AWS Kendra. The document_metadata_configuration_updates block is omitted 
  # here to maintain these defaults.
}
```

