# Variables for configuration
variable "hosted_zone_id" {
  description = "The ID of the hosted zone to apply the traffic policy to."
  type        = string
}

variable "domain_name" {
  description = "The domain name (e.g., www.example.com) to associate with the traffic policy."
  type        = string
}

# 1. Create the Traffic Policy Document
# This example implements a Latency-based routing policy.
data "aws_route53_traffic_policy_document" "latency_policy" {
  # The record type for the DNS records created by this policy
  record_type = "CNAME"

  # Define the endpoints (destinations for the traffic)
  endpoint {
    id     = "endpoint_us_east_1"
    value  = "us-east-1-app.example.com"
    type   = "aws:external" # Use 'aws:elb:loadbalancer' for ELBs
    region = "us-east-1"
  }

  endpoint {
    id     = "endpoint_us_west_2"
    value  = "us-west-2-app.example.com"
    type   = "aws:external"
    region = "us-west-2"
  }

  # Define the rules to route traffic to the endpoints
  rule {
    type = "latency"

    # Define branches based on latency region
    item {
      branch {
        condition {
          latency_region = "us-east-1"
        }
        endpoint {
          id = "endpoint_us_east_1"
        }
      }

      branch {
        condition {
          latency_region = "us-west-2"
        }
        endpoint {
          id = "endpoint_us_west_2"
        }
      }

      # Default behavior (e.g., if region doesn't match)
      branch {
        endpoint {
          id = "endpoint_us_east_1" # Default to us-east-1
        }
      }
    }
  }
}

# 2. Create the Traffic Policy
resource "aws_route53_traffic_policy" "main" {
  name    = "latency-routing-policy"
  comment = "Routes traffic to the nearest region based on latency"

  # Pass the JSON generated from the document data source
  document = data.aws_route53_traffic_policy_document.latency_policy.json
}

# 3. Create a Traffic Policy Instance
# This applies the specific policy version to a Hosted Zone and Record Name
resource "aws_route53_traffic_policy_instance" "example" {
  hosted_zone_id          = var.hosted_zone_id
  name                   = var.domain_name
  traffic_policy_id      = aws_route53_traffic_policy.main.id
  traffic_policy_version = aws_route53_traffic_policy.main.latest_version
  ttl                    = 60
}

