extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    null = {
      source  = "hashicorp/null"
      version = "~> 3.0"
    }
  }
}

variable "cluster_name" {
  description = "The name of the EKS cluster"
  type        = string
}

variable "subnet_ids" {
  description = "A list of subnet IDs to associate with the Fargate profile"
  type        = list(string)
}

# Data source to retrieve EKS cluster information
data "aws_eks_cluster" "cluster" {
  name = var.cluster_name
}

# Data source to retrieve EKS cluster authentication token
data "aws_eks_cluster_auth" "cluster" {
  name = var.cluster_name
}

# IAM Role for EKS Fargate Pod Execution
resource "aws_iam_role" "fargate_pod_execution_role" {
  name = "${var.cluster_name}-fargate-pod-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks-fargate-pods.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the AmazonEKSFargatePodExecutionRolePolicy
resource "aws_iam_role_policy_attachment" "fargate_pod_execution_attach" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
  role       = aws_iam_role.fargate_pod_execution_role.name
}

# Ensure the specified subnets have the required resource tag for cluster association
resource "aws_ec2_tag" "subnet_cluster_tag" {
  for_each = toset(var.subnet_ids)

  resource_id = each.value
  key         = "kubernetes.io/cluster/${var.cluster_name}"
  value       = "shared"
}

# Define the EKS Fargate Profile for the kube-system namespace
resource "aws_eks_fargate_profile" "kube_system_profile" {
  cluster_name           = var.cluster_name
  fargate_profile_name   = "kube-system-profile"
  pod_execution_role_arn = aws_iam_role.fargate_pod_execution_role.arn
  subnet_ids             = var.subnet_ids

  selector {
    namespace = "kube-system"
  }

  # Ensure the profile is created before patching
  depends_on = [
    aws_ec2_tag.subnet_cluster_tag
  ]
}

# Null resource to patch CoreDNS
resource "null_resource" "patch_coredns" {
  depends_on = [
    aws_eks_fargate_profile.kube_system_profile
  ]

  # Triggers a re-run whenever the cluster version or profile ID changes
  triggers = {
    cluster_version = data.aws_eks_cluster.cluster.version
    profile_id      = aws_eks_fargate_profile.kube_system_profile.id
  }

  provisioner "local-exec" {
    interpreter = ["/bin/bash", "-c"]
    command     = <<EOT
      # Write a temporary kubeconfig file
      cat > /tmp/kubeconfig-temp <<EOF
      apiVersion: v1
      kind: Config
      clusters:
      - cluster:
          certificate-authority-data: ${data.aws_eks_cluster.cluster.certificate_authority[0].data}
          server: ${data.aws_eks_cluster.cluster.endpoint}
        name: ${var.cluster_name}
      contexts:
      - context:
          cluster: ${var.cluster_name}
          user: ${var.cluster_name}
        name: ${var.cluster_name}
      current-context: ${var.cluster_name}
      users:
      - name: ${var.cluster_name}
        user:
          token: ${data.aws_eks_cluster_auth.cluster.token}
      EOF

      # Patch the CoreDNS deployment
      export KUBECONFIG=/tmp/kubeconfig-temp
      kubectl -n kube-system patch deployment coredns -p '{"spec":{"template":{"metadata":{"annotations":{"eks.amazonaws.com/fargate-profile":"kube-system"}}}}}'

      # Clean up
      rm /tmp/kubeconfig-temp
    EOT
  }
}

