# IAM policy document for assuming the role by EKS pods
data "aws_iam_policy_document" "example" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["pods.eks.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]

    condition {
      test     = "ArnLike"
      variable = "aws:SourceArn"
      values   = ["arn:aws:eks:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:cluster/example"]
    }
  }
}

# IAM role using the assume role policy document
resource "aws_iam_role" "example" {
  name               = "example"
  assume_role_policy = data.aws_iam_policy_document.example.json
}

# Attach S3 read-only access policy to the role
resource "aws_iam_role_policy_attachment" "example" {
  role       = aws_iam_role.example.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# EKS pod identity association linking the role to the cluster, namespace, and service account
resource "aws_eks_pod_identity_association" "example" {
  cluster_name    = "example"
  namespace       = "default"
  service_account = "example-service-account"
  role_arn        = aws_iam_role.example.arn
}

