# VPC Configuration
resource "aws_vpc" "demo_eks_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "demo-eks-vpc"
  }
}

resource "aws_subnet" "demo_eks_subnet_1" {
  vpc_id                  = aws_vpc.demo_eks_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "demo-eks-subnet-1"
  }
}

resource "aws_subnet" "demo_eks_subnet_2" {
  vpc_id                  = aws_vpc.demo_eks_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "demo-eks-subnet-2"
  }
}

resource "aws_internet_gateway" "demo_eks_igw" {
  vpc_id = aws_vpc.demo_eks_vpc.id
}

resource "aws_route_table" "demo_eks_rt" {
  vpc_id = aws_vpc.demo_eks_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.demo_eks_igw.id
  }
}

resource "aws_route_table_association" "demo_eks_rta_1" {
  subnet_id      = aws_subnet.demo_eks_subnet_1.id
  route_table_id = aws_route_table.demo_eks_rt.id
}

resource "aws_route_table_association" "demo_eks_rta_2" {
  subnet_id      = aws_subnet.demo_eks_subnet_2.id
  route_table_id = aws_route_table.demo_eks_rt.id
}

resource "aws_security_group" "demo_eks_cluster_sg" {
  name        = "demo-eks-cluster-sg"
  description = "Communication between the cluster control plane and nodes"
  vpc_id      = aws_vpc.demo_eks_vpc.id

  tags = {
    Name = "demo-eks-cluster-sg"
  }
}

# IAM Role for EKS Cluster
resource "aws_iam_role" "demo_eks" {
  name = "demo_eks"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })
}

# Attach IAM Policies
resource "aws_iam_role_policy_attachment" "cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.demo_eks.name
}

resource "aws_iam_role_policy_attachment" "vpc_resource_controller" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSVPCResourceController"
  role       = aws_iam_role.demo_eks.name
}

# EKS Cluster
resource "aws_eks_cluster" "demo_eks" {
  name     = "demo_eks"
  role_arn = aws_iam_role.demo_eks.arn
  version  = "1.29"

  vpc_config {
    subnet_ids = [
      aws_subnet.demo_eks_subnet_1.id,
      aws_subnet.demo_eks_subnet_2.id
    ]
    security_group_ids = [aws_security_group.demo_eks_cluster_sg.id]
    endpoint_public_access  = true
    endpoint_private_access = false
  }

  # Ensure that IAM Role policies are applied before the cluster is created
  depends_on = [
    aws_iam_role_policy_attachment.cluster_policy,
    aws_iam_role_policy_attachment.vpc_resource_controller
  ]
}
```

