provider "aws" {
  region = "us-east-1"
}

variable "blocked_ip" {
  description = "The specific IP address to deny access to the S3 bucket."
  default     = "203.0.113.0/24" # Example IP address (TEST-NET-3)
}

resource "aws_s3_bucket" "my_bucket" {
  bucket = "my_bucket"
}

resource "aws_s3_bucket_policy" "deny_ip_policy" {
  bucket = aws_s3_bucket.my_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Id      = "DenySpecificIPPolicy"
    Statement = [
      {
        Sid    = "DenyAccessFromSpecificIP"
        Effect = "Deny"
        Principal = "*"
        Action = "s3:*"
        Resource = [
          aws_s3_bucket.my_bucket.arn,
          "${aws_s3_bucket.my_bucket.arn}/*"
        ]
        Condition = {
          IpAddress = {
            "aws:SourceIp" = var.blocked_ip
          }
        }
      }
    ]
  })
}

