terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

resource "aws_s3_bucket" "infra" {
  bucket = "wellcomecollection-platform-infra"

  # Preventive destruction measure to stop accidental deletion via Terraform
  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_s3_bucket_ownership_controls" "infra" {
  bucket = aws_s3_bucket.infra.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "infra" {
  depends_on = [aws_s3_bucket_ownership_controls.infra]
  bucket     = aws_s3_bucket.infra.id
  acl        = "private"
}

resource "aws_s3_bucket_versioning" "infra" {
  bucket = aws_s3_bucket.infra.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "infra" {
  bucket = aws_s3_bucket.infra.id

  # Rule 1: Automatic deletion of objects with 'tmp/' prefix after 30 days
  rule {
    id     = "delete-tmp-files"
    status = "Enabled"

    filter {
      prefix = "tmp/"
    }

    expiration {
      days = 30
    }
  }

  # Rule 2: Lifecycle rules for versioning
  rule {
    id     = "manage-versions"
    status = "Enabled"

    # Transition old versions to STANDARD_IA after 30 days
    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "STANDARD_IA"
    }

    # Delete noncurrent versions after 90 days
    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }
}

