  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Route Table for Public Subnet
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Elastic IP for NAT Gateway
resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

# NAT Gateway
resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "main-nat"
  }
}

# Route Table for Private Subnet
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }

  tags = {
    Name = "private-rt"
  }
}

resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# Security Group
resource "aws_security_group" "fleet_sg" {
  name        = "fleet-sg"
  description = "Allow SSH inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "fleet-sg"
  }
}

# Launch Template
resource "aws_launch_template" "fleet_template" {
  name          = "fleet-launch-template"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  key_name      = "example-key-pair" # Replace with your actual key pair name

  network_interfaces {
    associate_public_ip_address = true
    security_groups             = [aws_security_group.fleet_sg.id]
  }

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "fleet-instance"
    }
  }
}

# EC2 Fleet
resource "aws_ec2_fleet" "example_fleet" {
  fleet_type = "instant"

  launch_template_config {
    launch_template_specification {
      id      = aws_launch_template.fleet_template.id
      version = "$Latest"
    }
    # Deploy instances across both subnets
    override {
      subnet_id = aws_subnet.public.id
    }
    override {
      subnet_id = aws_subnet.private.id
    }
  }

  target_capacity_specification {
    total_target_capacity      = 9
    default_target_capacity_type = "spot"
  }

  on_demand_options {
    min_target_capacity = 5
  }

  spot_options {
    # Remaining capacity (4) will be Spot
  }

  tags = {
    Name = "ec2-fleet-example"
  }
}

