  availability_zone       = "us-east-1a" # Change AZ as needed

  tags = {
    Name = "public-subnet"
  }
}

# Elastic IP for NAT Gateway
resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

# NAT Gateway
resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "main-nat-gateway"
  }

  depends_on = [aws_internet_gateway.igw]
}

# Private Subnet (for EC2 and EFS)
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a" # Change AZ as needed

  tags = {
    Name = "private-subnet"
  }
}

# Route Table for Public Subnet
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-rt"
  }
}

# Route Table for Private Subnet
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }

  tags = {
    Name = "private-rt"
  }
}

# Route Table Associations
resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# EFS File System
resource "aws_efs_file_system" "shared" {
  creation_token = "shared-efs-storage"

  tags = {
    Name = "shared-efs"
  }
}

# EFS Mount Target (in Private Subnet)
resource "aws_efs_mount_target" "private" {
  file_system_id  = aws_efs_file_system.shared.id
  subnet_id       = aws_subnet.private.id
  security_groups = [aws_security_group.efs.id]
}

# Security Group for EFS (Allow NFS traffic)
resource "aws_security_group" "efs" {
  description = "Allow NFS inbound traffic for EFS"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "NFS from EC2 Security Group"
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    security_groups = [aws_security_group.ec2.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "efs-sg"
  }
}

# Security Group for EC2 (SSH + Outbound + NFS)
resource "aws_security_group" "ec2" {
  description = "Allow SSH and outbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "SSH from MyIP"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-sg"
  }
}

# EC2 Instances (2x)
resource "aws_instance" "linux_instance" {
  count         = 2
  ami           = data.aws_ami.amazon_linux_2023.id
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.private.id
  vpc_security_group_ids = [aws_security_group.ec2.id]

  # User data to mount EFS
  user_data = <<-EOF
              #!/bin/bash
              # Install EFS utils
              dnf install -y amazon-efs-utils
              # Create mount point
              mkdir -p /mnt/efs
              # Mount EFS
              mount -t efs -o tls ${aws_efs_file_system.shared.id}:/ /mnt/efs
              # Add to fstab for persistence
              echo "${aws_efs_file_system.shared.id}:/ /mnt/efs efs defaults,_netdev 0 0" >> /etc/fstab
              EOF

  tags = {
    Name = "linux-instance-${count.index + 1}"
  }

  depends_on = [aws_efs_mount_target.private]
}
```

