  description = "Identifier for the Memcached cluster"
}

variable "node_type" {
  default = "cache.t2.medium"
  description = "Instance type for the cache nodes"
}

variable "num_cache_nodes" {
  default = 2
  description = "Number of cache nodes in the cluster"
}

variable "vpc_id" {
  description = "VPC ID where the cluster will be deployed"
}

variable "subnet_ids" {
  type        = list(string)
  description = "List of subnet IDs for the cluster subnet group"
}

# Security Group for Memcached
resource "aws_security_group" "memcached_sg" {
  name        = "${var.cluster_id}-sg"
  description = "Security group for Memcached cluster"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 11211
    to_port     = 11211
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.cluster_id}-sg"
  }
}

# Subnet Group for Memcached
