provider "aws" {
  region = "us-east-1"
}

data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  vpc_id = data.aws_vpc.default.id
}

resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  description = "Allow Redshift inbound traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_redshift_subnet_group" "default" {
  name       = "tf-redshift-subnet-group"
  subnet_ids = slice(data.aws_subnets.default.ids, 0, 2)

  tags = {
    Name = "Terraform Redshift Subnet Group"
  }
}

resource "aws_iam_role" "redshift_iam" {
  name = "redshift_iam_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_attach" {
  role       = aws_iam_role.redshift_iam.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRedshiftServiceRolePolicy"
}

resource "aws_redshift_cluster" "default" {
  cluster_identifier          = "tf-redshift-cluster"
  database_name               = "mydb"
  master_username             = "admin"
  master_password             = "Terraform123!"
  node_type                   = "dc2.large"
  cluster_type                = "multi-node"
  number_of_nodes             = 2
  publicly_accessible         = true
  cluster_subnet_group_name   = aws_redshift_subnet_group.default.name
  vpc_security_group_ids      = [aws_security_group.redshift_sg.id]
  iam_roles                   = [aws_iam_role.redshift_iam.arn]

  # Limit concurrency scaling to 60 minutes (3600 seconds)
  concurrency_scaling_max_usage_seconds = 3600

  skip_final_snapshot         = true
  tags = {
    Environment = "terraform-demo"
  }
}

