extracted_code:
provider "aws" {
  region = "us-east-1"
}

# VPC for the Redshift Cluster
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Internet Gateway for Public Access (Optional, but common for Redshift)
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.redshift_vpc.id
}

# Subnet in us-east-1a
resource "aws_subnet" "subnet_a" {
  vpc_id                  = aws_vpc.redshift_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "redshift-subnet-us-east-1a"
  }
}

# Subnet in us-east-1b
resource "aws_subnet" "subnet_b" {
  vpc_id                  = aws_vpc.redshift_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "redshift-subnet-us-east-1b"
  }
}

# Route Table to allow internet access
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.redshift_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

# Associate Route Table with Subnets
resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.subnet_a.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.subnet_b.id
  route_table_id = aws_route_table.public_rt.id
}

# Redshift Subnet Group spanning multiple AZs
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-ha-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Redshift HA Subnet Group"
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound Redshift traffic"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Random Password for Master User
resource "random_password" "password" {
  length  = 20
  special = true
}

# Highly Available Redshift Cluster
resource "aws_redshift_cluster" "default" {
  cluster_identifier          = "tf-redshift-ha-cluster"
  database_name               = "mydb"
  master_username             = "admin"
  master_password             = random_password.password.result
  node_type                   = "dc2.large"
  cluster_type                = "multi-node"
  number_of_nodes             = 2
  cluster_subnet_group_name   = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids      = [aws_security_group.redshift_sg.id]
  publicly_accessible         = true
  skip_final_snapshot         = true
  iam_roles                   = [] # Add IAM roles if needed for S3 access etc.

  tags = {
    Environment = "production"
  }
}

