extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

provider "aws" {
  alias  = "replica"
  region = "us-east-2"
}

# Generate a secure password for the master user
resource "random_password" "master_password" {
  length  = 16
  special = true
}

# KMS Key in the replica region (us-east-2) to encrypt the replicated snapshots
resource "aws_kms_key" "replica_key" {
  provider = aws.replica

  description             = "KMS Key for Redshift Snapshot Replication"
  deletion_window_in_days = 10
}

resource "aws_kms_alias" "replica_key_alias" {
  provider = aws.replica

  name          = "alias/redshift-replica-key"
  target_key_id = aws_kms_key.replica_key.key_id
}

# Snapshot Copy Grant in the replica region (us-east-2)
# This allows Redshift to copy snapshots to this region using the KMS key
resource "aws_redshift_snapshot_copy_grant" "replica_grant" {
  provider = aws.replica

  snapshot_copy_grant_name = "redshift-replica-grant"
  kms_key_id               = aws_kms_key.replica_key.arn
}

# The Main Redshift Cluster in us-east-1
resource "aws_redshift_cluster" "main" {
  cluster_identifier = "main-redshift-cluster"
  database_name      = "mydb"
  master_username    = "admin"
  master_password    = random_password.master_password.result
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  # Enable automated cross-region snapshot replication
  snapshot_copy {
    destination_region = "us-east-2"
    grant_name         = aws_redshift_snapshot_copy_grant.replica_grant.snapshot_copy_grant_name
    retention_period   = 5 # Retain replicated snapshots for 5 days
  }

  # Configuration to ensure final snapshot on destroy (optional, recommended for safety)
  final_snapshot_identifier = "main-redshift-final-snapshot"
  skip_final_snapshot       = false

  tags = {
    Environment = "Production"
    Replicated  = "true"
  }
}

