# VPC and Subnet Resources (Required for Redshift Cluster)
resource "aws_vpc" "redshift_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "redshift-subnet-2"
  }
}

# Redshift Subnet Group
resource "aws_redshift_subnet_group" "subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Name = "My Redshift Subnet Group"
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic for Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Redshift Cluster
resource "aws_redshift_cluster" "default" {
  cluster_identifier      = "tf-redshift-cluster"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "Test1234ChangeMe" # In production, use a sensitive variable or SSM parameter
  node_type               = "dc2.large"
  cluster_type            = "multi-node"
  number_of_nodes         = 2
  cluster_subnet_group_name = aws_redshift_subnet_group.subnet_group.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  publicly_accessible       = true
  skip_final_snapshot       = true

  tags = {
    Environment = "test"
  }
}

# Redshift Endpoint Access
resource "aws_redshift_endpoint_access" "example" {
  cluster_identifier = aws_redshift_cluster.default.cluster_identifier
  resource_owner     = data.aws_caller_identity.current.account_id
  subnet_group_name  = aws_redshift_subnet_group.subnet_group.name
  endpoint_name      = "redshift-endpoint"
}
```

