provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lambda Execution
resource "aws_iam_role" "lambda_exec" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic execution policy to the role
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 2. Create the Lambda Function Code (Example in Python)
resource "local_file" "lambda_script" {
  filename = "${path.module}/lambda_function.py"
  content  = <<-EOT
import json

def lambda_handler(event, context):
    print("Lambda invoked at: " + str(context.time))
    return {
        'statusCode': 200,
        'body': json.dumps('Hello from scheduled Lambda!')
    }
  EOT
}

# 3. Package the code into a Zip file
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_script.filename
  output_path = "${path.module}/lambda_function_payload.zip"
}

# 4. Create the Lambda Function
resource "aws_lambda_function" "this" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "scheduled_lambda_function"
  role             = aws_iam_role.lambda_exec.arn
  handler          = "lambda_function.lambda_handler"
  runtime          = "python3.9"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
}

# 5. Create EventBridge (CloudWatch Events) Rule for 15-minute schedule
resource "aws_cloudwatch_event_rule" "every_15_minutes" {
  name                = "lambda-every-15-minutes"
  description         = "Fires every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

# 6. Set the Lambda as the target for the rule
