terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for DAX Service
resource "aws_iam_role" "dax_role" {
  name = "dax-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

# Attach necessary DynamoDB access policy
resource "aws_iam_role_policy_attachment" "dax_policy_attach" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

# Data source to retrieve default VPC
data "aws_vpc" "default" {
  default = true
}

# Data source to retrieve subnets in the default VPC
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# DAX Subnet Group
resource "aws_dax_subnet_group" "dax_subnet_group" {
  name = "example-dax-subnet-group"
  # DAX requires subnets in different AZs; we grab 3 for availability
  subnet_ids = slice(data.aws_subnets.default.ids, 0, 3)
}

# Security Group for DAX
resource "aws_security_group" "dax_sg" {
  name        = "dax-security-group"
  description = "Allow traffic for DAX cluster"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.default.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# DAX Cluster
resource "aws_dax_cluster" "example" {
  cluster_name       = "example-dax-cluster"
  iam_arn            = aws_iam_role.dax_role.arn
  node_type          = "dax.r4.large"
  replication_factor = 1
  subnet_group_name  = aws_dax_subnet_group.dax_subnet_group.name
  security_group_ids = [aws_security_group.dax_sg.id]

  tags = {
    Name = "example-dax-cluster"
  }
}

