resource "aws_sagemaker_domain" "this" {
  domain_name = "example-sagemaker-domain"

  # VPC configuration where the domain will reside
  vpc_id     = var.vpc_id
  subnet_ids = var.subnet_ids

  # Authentication mode (IAM or SSO)
  auth_mode = "IAM"

  # Default settings for users created in this domain
  default_user_settings {
    execution_role = var.sagemaker_execution_role_arn

    # Jupyter Server application settings
    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "system"
      }
    }

    # Kernel Gateway application settings
    kernel_gateway_app_settings {
      default_resource_spec {
        instance_type = "system"
      }
    }

    # Sharing settings for spaces
    sharing_settings {
      notebook_output_option = "Allowed"
    }
  }

  tags = {
    Name        = "example-sagemaker-domain"
    Environment = "dev"
  }
}

# Variable definitions
variable "vpc_id" {
  description = "The ID of the VPC to associate with the Domain."
  type        = string
}

variable "subnet_ids" {
  description = "The IDs of the subnets to associate with the Domain."
  type        = list(string)
}

variable "sagemaker_execution_role_arn" {
  description = "The ARN of the execution role for the Domain."
  type        = string
}

