  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for SageMaker to access model artifacts and containers
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-kmeans-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the SageMaker Full Access policy for demonstration purposes
resource "aws_iam_role_policy_attachment" "sagemaker_policy_attach" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# S3 Bucket to store model artifacts
# In a real scenario, you would upload your trained model (model.tar.gz) here
resource "aws_s3_bucket" "model_artifacts" {
  bucket = "my-kmeans-model-artifacts-bucket"
}

resource "aws_s3_object" "model_data" {
  bucket = aws_s3_bucket.model_artifacts.bucket
  key    = "model.tar.gz"
  source = "/dev/null" # Placeholder, replace with actual model file path
}

# The SageMaker Model Resource running the K-Means image
resource "aws_sagemaker_model" "kmeans_model" {
  name               = "kmeans-clustering-model"
  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  define_primary_container {
    # This is the ECR URI for the SageMaker K-Means algorithm in us-east-1.
    # Note: The Account ID and Region in the URI must match your AWS Region.
    image = "683313688378.dkr.ecr.us-east-1.amazonaws.com/kmeans:1"

    # S3 URI where the model artifacts are stored
    model_data_url = "s3://${aws_s3_bucket.model_artifacts.bucket}/${aws_s3_object.model_data.key}"
  }

  enable_network_isolation = false
}

