provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for SageMaker to access model artifacts and container images
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_policy_attachment" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 2. SageMaker Model
# Defines the model artifacts (S3) and the inference image (ECR)
resource "aws_sagemaker_model" "my_model" {
  name               = "my-model"
  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  primary_container {
    # Replace with your ECR image URI
    image          = "123456789012.dkr.ecr.us-east-1.amazonaws.com/my-inference-image:latest"
    # Replace with your S3 model artifacts path
    model_data_url = "s3://my-model-bucket/model.tar.gz"
  }
}

# 3. SageMaker Endpoint Configuration
# Defines the hardware instance type and scaling settings
resource "aws_sagemaker_endpoint_config" "my_endpoint_config" {
  name = "my-endpoint-config"

  production_variants {
    variant_name           = "production-variant"
    model_name             = aws_sagemaker_model.my_model.name
    initial_instance_count = 1
    instance_type          = "ml.t2.medium"
  }
}

# 4. SageMaker Endpoint
# Deploys the endpoint based on the configuration
resource "aws_sagemaker_endpoint" "my_endpoint" {
  name                 = "my-endpoint"
  endpoint_config_name = aws_sagemaker_endpoint_config.my_endpoint_config.name

  # Ensure endpoint creation waits until the service is available
  tags = {
    Purpose = "Inference"
  }
}

