provider "aws" {
  region = "us-east-1"
}

# VPC and Networking Resources (Boilerplate for Elasticache)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "main" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
}

resource "aws_security_group" "main" {
  vpc_id = aws_vpc.main.id
}

# Elasticache Subnet Group
resource "aws_elasticache_subnet_group" "main" {
  name        = "example-subnet-group"
  description = "Example subnet group"
  subnet_ids  = [aws_subnet.main.id]
}

# Elasticache User with IAM Authentication
# 'no_password_required' set to true indicates the user authenticates via IAM
resource "aws_elasticache_user" "iam_user" {
  user_id        = "iam-user-id"
  user_name      = "iam_user"
  access_string  = "on ~* &* +@all" # Permissions string
  engine         = "redis"
  no_password_required = true 
}

# User Group to associate the user
resource "aws_elasticache_user_group" "main" {
  user_group_id = "main-user-group"
  engine        = "redis"
  user_ids      = [aws_elasticache_user.iam_user.user_id]
}

# Elasticache Replication Group
resource "aws_elasticache_replication_group" "main" {
  replication_group_id          = "example-replication-group"
  description                   = "Example elasticache cluster with IAM auth"
  node_type                     = "cache.t3.micro"
  num_cache_clusters            = 1
  engine                        = "redis"
  engine_version                = "6.x" # IAM auth requires Redis 6.0+

  # Networking
  subnet_group_name             = aws_elasticache_subnet_group.main.name
  security_group_ids            = [aws_security_group.main.id]

  # Authentication Configuration
  # Transit encryption must be enabled for IAM authentication
  transit_encryption_enabled    = true

  # Attach the user group containing the IAM user
  user_group_ids                = [aws_elasticache_user_group.main.user_group_id]
}

