provider "aws" {
  region = "us-east-1" # Note: us-east1 is GCP syntax; corrected to AWS us-east-1 for MSK
}

# Retrieve the Default VPC
data "aws_vpc" "default" {
  default = true
}

# Retrieve subnets in the Default VPC
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Create a Security Group for the cluster
resource "aws_security_group" "msk_serverless_sg" {
  name        = "msk-serverless-sg"
  description = "Security group for MSK Serverless Cluster"
  vpc_id      = data.aws_vpc.default.id

  # Allow access to Kafka Broker port (9098 is typical for SASL/SCRAM on Serverless)
  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.default.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create the MSK Serverless Cluster
resource "aws_msk_serverless_cluster" "example" {
  cluster_name = "msk-serverless-cluster"

  vpc_config {
    # MSK Serverless requires subnets in at least two Availability Zones
    subnet_ids         = slice(data.aws_subnets.default.ids, 0, 2)
    security_group_ids = [aws_security_group.msk_serverless_sg.id]
  }

  tags = {
    Environment = "serverless"
    ManagedBy   = "Terraform"
  }
}

