terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-serverless-subnet-${count.index}"
  }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Allow inbound traffic for MSK Serverless"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "TCP"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-serverless-sg"
  }
}

resource "aws_kms_key" "msk_encryption" {
  description             = "MSK Serverless Data Encryption Key"
  deletion_window_in_days = 10

  tags = {
    Name = "msk-serverless-kms"
  }
}

resource "aws_msk_cluster" "serverless" {
  cluster_name           = "msk-serverless-cluster"
  cluster_type           = "serverless"
  kafka_version          = "2.8.1"

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_encryption.arn
  }

  client_authentication {
    sasl {
      scram = true
    }
  }

  serverless {
    vpc_config {
      subnet_ids         = aws_subnet.msk_subnet[*].id
      security_group_ids = [aws_security_group.msk_sg.id]
    }
  }

  tags = {
    Name = "msk-serverless-cluster"
  }
}

