provider "aws" {
  region = "us-east-1"
}

# Random suffix for unique naming
resource "random_suffix" "this" {
  length = 4
}

# --- Networking ---
resource "aws_vpc" "this" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc-${random_suffix.this.result}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "this" {
  count             = 3
  vpc_id            = aws_vpc.this.id
  cidr_block        = cidrsubnet(aws_vpc.this.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "msk-subnet-${count.index}-${random_suffix.this.result}"
  }
}

resource "aws_security_group" "this" {
  name        = "msk-sg-${random_suffix.this.result}"
  description = "Allow MSK traffic"
  vpc_id      = aws_vpc.this.id

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.this.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg-${random_suffix.this.result}"
  }
}

# --- KMS Key for Encryption at Rest ---
resource "aws_kms_key" "this" {
  description             = "MSK Cluster Encryption Key"
  deletion_window_in_days = 10
  policy                  = <<POLICY
{
  "Version": "2012-10-17",
  "Id": "msk-key-policy",
  "Statement": [
    {
      "Sid": "Enable IAM User Permissions",
      "Effect": "Allow",
      "Principal": {
        "AWS": "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
      },
      "Action": "kms:*",
      "Resource": "*"
    },
    {
      "Sid": "Allow MSK to use the key",
      "Effect": "Allow",
      "Principal": {
        "Service": "kafka.amazonaws.com"
      },
      "Action": [
        "kms:Decrypt",
        "kms:DescribeKey",
        "kms:Encrypt",
        "kms:GenerateDataKey*"
      ],
      "Resource": "*"
    }
  ]
}
POLICY
}

resource "aws_kms_alias" "this" {
  name          = "alias/msk-key-${random_suffix.this.result}"
  target_key_id = aws_kms_key.this.key_id
}

data "aws_caller_identity" "current" {}

# --- S3 Bucket ---
resource "aws_s3_bucket" "this" {
  bucket = "msk-firehose-logs-${random_suffix.this.result}"
}

resource "aws_s3_bucket_ownership_controls" "this" {
  bucket = aws_s3_bucket.this.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "this" {
  depends_on = [aws_s3_bucket_ownership_controls.this]
  bucket     = aws_s3_bucket.this.id
  acl        = "private"
}

# --- Kinesis Firehose ---
resource "aws_iam_role" "firehose" {
  name = "firehose-role-${random_suffix.this.result}"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "firehose.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "firehose_s3" {
  name = "firehose-s3-policy"
  role = aws_iam_role.firehose.id

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "s3:AbortMultipartUpload",
        "s3:GetBucketLocation",
        "s3:GetObject",
        "s3:ListBucket",
        "s3:ListBucketMultipartUploads",
        "s3:PutObject"
      ],
      "Resource": [
        "${aws_s3_bucket.this.arn}",
        "${aws_s3_bucket.this.arn}/*"
      ]
    }
  ]
}
EOF
}

resource "aws_kinesis_firehose_delivery_stream" "this" {
  name        = "msk-firehose-stream-${random_suffix.this.result}"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose.arn
    bucket_arn = aws_s3_bucket.this.arn
    # buffering_size or interval can be configured here
  }
}

# --- CloudWatch Log Group ---
resource "aws_cloudwatch_log_group" "this" {
  name              = "/aws/msk/cluster-${random_suffix.this.result}"
  retention_in_days = 7
}

# --- IAM Role for MSK Logging ---
resource "aws_iam_role" "msk_logging" {
  name = "msk-logging-role-${random_suffix.this.result}"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "kafka.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "msk_logging" {
  name = "msk-logging-policy"
  role = aws_iam_role.msk_logging.id

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": "arn:aws:logs:*:*:*"
    },
    {
      "Effect": "Allow",
      "Action": [
        "firehose:PutRecord"
      ],
      "Resource": "${aws_kinesis_firehose_delivery_stream.this.arn}"
    }
  ]
}
EOF

# --- MSK Configuration ---
resource "aws_msk_configuration" "this" {
  kafka_versions = ["2.8.1"]
  name           = "msk-config-${random_suffix.this.result}"

  server_properties = <<PROPERTIES
auto.create.topics.enable=true
log.segment.bytes=1073741824
log.retention.hours=168
default.replication.factor=3
min.insync.replicas=2
num.partitions=1
PROPERTIES
}

# --- MSK Cluster ---
resource "aws_msk_cluster" "this" {
  cluster_name           = "msk-cluster-${random_suffix.this.result}"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  configuration_info {
    arn      = aws_msk_configuration.this.arn
    revision = aws_msk_configuration.this.latest_revision
  }

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.this[*].id
    security_groups = [aws_security_group.this.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.this.arn
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.this.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.this.name
      }
    }
  }

  tags = {
    Name = "msk-cluster-${random_suffix.this.result}"
  }
}
