}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# VPC and Networking (Prerequisites for MSK)
# ------------------------------------------------------------------------------
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

resource "aws_security_group" "msk_sg" {
  name_prefix = "msk-sg-"
  vpc_id      = aws_vpc.msk_vpc.id

  # Allow communication within the VPC (Broker to Broker, Connect to Broker)
  ingress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    self      = true
  }

  # Allow traffic from Connect Workers (in same VPC)
  ingress {
    from_port = 9094 # SASL/SCRAM port
    to_port   = 9096
    protocol  = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# ------------------------------------------------------------------------------
# Secrets Manager (For SASL/SCRAM Authentication)
# ------------------------------------------------------------------------------
resource "aws_secretsmanager_secret" "msk_secret" {
  name = "amazon-msk-msk-connect-scram-secret"
}

resource "aws_secretsmanager_secret_version" "msk_secret_version" {
  secret_id = aws_secretsmanager_secret.msk_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = "Password123"
  })
}

# ------------------------------------------------------------------------------
# MSK Cluster
# ------------------------------------------------------------------------------
resource "aws_msk_cluster" "example" {
  cluster_name           = "example-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.t3.small"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 20
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  client_authentication {
    sasl {
      scram = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  tags = {
    Name = "example-msk-cluster"
  }
}

# Supporting resources for MSK
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/cluster/example"
  retention_in_days = 7
}

resource "aws_kms_key" "msk_key" {
  description             = "MSK Cluster Encryption Key"
  deletion_window_in_days = 10
}

# ------------------------------------------------------------------------------
# IAM Role for MSK Connect
# ------------------------------------------------------------------------------
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connect_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonMSKConnectServiceRole"
  role       = aws_iam_role.msk_connect_role.name
}

resource "aws_iam_role_policy" "msk_connect_secrets_policy" {
  name = "msk-connect-secrets-policy"
  role = aws_iam_role.msk_connect_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Resource = aws_secretsmanager_secret.msk_secret.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kafka:CreateCluster",
          "kafka:DescribeCluster",
          "kafka:DescribeClusterV2",
          "kafka:GetBootstrapBrokers",
          "kafka:ListClusters",
          "kafka:ListClustersV2"
        ]
        Resource = aws_msk_cluster.example.arn
      }
    ]
  })
}

# ------------------------------------------------------------------------------
# MSK Connect Custom Plugin
# ------------------------------------------------------------------------------

# Variables for the location of the Debezium Zip file
variable "debezium_zip_s3_bucket" {
  description = "The S3 bucket containing the debezium.zip"
  type        = string
  default     = "my-debezium-plugins-bucket" # Replace with actual bucket
}

variable "debezium_zip_s3_key" {
  description = "The S3 key path for the debezium.zip"
  type        = string
  default     = "connectors/debezium.zip"     # Replace with actual key
}

resource "aws_mskconnect_custom_plugin" "debezium" {
  name         = "debezium-postgres-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = "arn:aws:s3:::${var.debezium_zip_s3_bucket}"
      file_key   = var.debezium_zip_s3_key
    }
  }
}

# ------------------------------------------------------------------------------
# MSK Connect Connector
# ------------------------------------------------------------------------------
resource "aws_mskconnect_connector" "example" {
  name = "debezium-source-connector"

  capacity {
    provisioned_capacity {
      mcu_count    = 1
      worker_count = 1
    }
  }

  connector_configuration = {
    "connector.class"              = "io.debezium.connector.postgresql.PostgresConnector"
    "database.hostname"            = "your-postgres-instance.us-east-1.rds.amazonaws.com"
    "database.port"                = "5432"
    "database.user"                = "postgresuser"
    "database.password"            = "postgrespassword"
    "database.dbname"              = "mydb"
    "topic.prefix"                 = "postgres-"
    "plugin.name"                  = "Postgres"
    "database.server.name"         = "my_postgres_server"
    "slot.name"                    = "debezium_slot"
    "database.history.kafka.topic" = "schema-changes.mydb"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.example.bootstrap_brokers_sasl_scram
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_sasl_scram

      vpc {
        subnet_ids = [aws_subnet.msk_subnet[0].id]
        security_groups = [aws_security_group.msk_sg.id]
      }

      authentication {
        sasl_scram {
          secret_arn = aws_secretsmanager_secret.msk_secret.arn
        }
      }
    }
  }

  kafka_client {
    authentication {
      sasl_scram {
        secret_arn = aws_secretsmanager_secret.msk_secret.arn
      }
    }
  }

  log_delivery {
    worker_log_delivery {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.connect_logs.name
      }
    }
  }

  plugin {
    custom_plugin {
      custom_plugin_arn = aws_mskconnect_custom_plugin.debezium.arn
      # Plugins usually require a specific revision, here we let AWS resolve to the latest of the ARN or implicitly use the only revision available.
      # Note: In explicit setups, one might use `revision` attribute inside custom_plugin if supported by specific provider version logic, 
      # but generally `custom_plugin_arn` + `custom_plugin` block is sufficient for the active revision.
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn

  depends_on = [aws_cloudwatch_log_group.connect_logs]
}

resource "aws_cloudwatch_log_group" "connect_logs" {
  name              = "/aws/msk-connect/connector/debezium-connector"
  retention_in_days = 7
}

