```hcl
provider "aws" {
  region = "us-east-1"
}

# --- VPC and Networking ---
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow MSK traffic"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9096
    to_port     = 9096
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- IAM Roles ---
resource "aws_iam_role" "firehose_role" {
  name = "firehose-delivery-role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "firehose.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "firehose_s3" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "kafkaconnect.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "msk_connect_policy" {
  role       = aws_iam_role.msk_connect_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonMSKConnectServiceRole"
}

# --- KMS Key for Encryption ---
resource "aws_kms_key" "msk_encryption" {
  description             = "MSK Cluster Encryption Key"
  deletion_window_in_days = 10
}

resource "aws_kms_alias" "msk_encryption_alias" {
  name          = "alias/msk-encryption-key"
  target_key_id = aws_kms_key.msk_encryption.key_id
}

# --- CloudWatch Log Group ---
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/cluster/logs"
  retention_in_days = 7
}

# --- S3 Bucket ---
resource "aws_s3_bucket" "data_bucket" {
  bucket = "msk-data-bucket-unique-id-12345"
}

# --- Kinesis Firehose ---
resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.data_bucket.arn
  }
}

# --- MSK Cluster ---
resource "aws_msk_cluster" "main" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_encryption.arn
    encryption_in_transit {
      client_broker = "PLAINTEXT"
      in_cluster    = true
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  tags = {
    Name = "terraform-msk"
  }
}

# --- MSK Connect Custom Plugin ---
# Note: The 'debezium.zip' must exist in the S3 bucket specified. 
# This configuration assumes the file is uploaded to the bucket created above.
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name        = "debezium-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.data_bucket.arn
      file_key   = "debezium.zip"
    }
  }
}

# --- MSK Connect Connector ---
resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-connector"
  capacity {
    autoscaling {
      max_worker_count = 2
      mcu_count        = 1
      min_worker_count = 1
      scale_in_policy  = 300
      scale_out_policy = 60
    }
  }

  connector_configuration = {
    "connector.class"          = "io.debezium.connector.mysql.MySqlConnector"
    "database.hostname"        = "your-mysql-endpoint"
    "database.port"            = "3306"
    "database.user"            = "user"
    "database.password"        = "password"
    "database.server.id"       = "184054"
    "database.server.name"     = "dbserver1"
    "database.include.list"    = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.main.bootstrap_brokers
    "database.history.kafka.topic"             = "schema-changes.inventory"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.main.bootstrap_brokers

      vpc {
        subnets = aws_subnet.msk_subnet[*].id
        security_groups = [aws_security_group.msk_sg.id]
      }
    }
  }

  kafka_client {
    plugin_location {
      custom_plugin {
        arn      = aws_mskconnect_custom_plugin.debezium_plugin.arn
        revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
      }
    }
  }

  log_delivery {
    worker_log_delivery {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
}
```

