backup_retention_period = 5
preferred_backup_window = "07:00-09:00"
skip_final_snapshot = true
}

response:
```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# Generate a secure password for the database
resource "random_password" "db_master_password" {
  length           = 16
  special          = true
  override_special = "_!%@"
}

# Create a DB Subnet Group
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "${var.cluster_name}-subnet-group"
  subnet_ids = var.subnet_ids

  tags = {
    Name = "${var.cluster_name}-subnet-group"
  }
}

# Create a Security Group for the Aurora Cluster
resource "aws_security_group" "aurora_security_group" {
  name        = "${var.cluster_name}-security-group"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL from VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.cluster_name}-security-group"
  }
}

# Create the Aurora PostgreSQL Cluster
resource "aws_rds_cluster" "aurora_cluster" {
  engine                = "aurora-postgresql"
  engine_version        = var.engine_version
  database_name         = var.db_name
  master_username       = var.master_username
  master_password       = random_password.db_master_password.result
  db_subnet_group_name  = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids = [aws_security_group.aurora_security_group.id]
  storage_encrypted     = true
  skip_final_snapshot   = true
  apply_immediately     = true

  tags = {
    Name = var.cluster_name
  }
}

# Create Instances in the Cluster
resource "aws_rds_cluster_instance" "aurora_instances" {
  count              = var.instance_count
  identifier         = "${var.cluster_name}-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora_cluster.id
  instance_class     = var.instance_class
  engine             = aws_rds_cluster.aurora_cluster.engine
  engine_version     = aws_rds_cluster.aurora_cluster.engine_version
  publicly_accessible = false
}

# Variables
variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "cluster_name" {
  description = "Name of the Aurora Cluster"
  type        = string
  default     = "aurora-postgres-cluster"
}

variable "engine_version" {
  description = "Aurora PostgreSQL version"
  type        = string
  default     = "15.4"
}

variable "db_name" {
  description = "Name of the initial database"
  type        = string
  default     = "mydb"
}

variable "master_username" {
  description = "Master username for the database"
  type        = string
  default     = "admin"
}

variable "instance_class" {
  description = "Instance class for the Aurora instances"
  type        = string
  default     = "db.t3.small"
}

variable "instance_count" {
  description = "Number of instances in the cluster"
  type        = number
  default     = 1
}

variable "vpc_id" {
  description = "VPC ID where the cluster will be deployed"
  type        = string
}

variable "subnet_ids" {
  description = "List of Subnet IDs for the DB Subnet Group"
  type        = list(string)
}

variable "allowed_cidr_blocks" {
  description = "List of CIDR blocks allowed to access the database"
  type        = list(string)
  default     = ["10.0.0.0/16"]
}

# Outputs
output "cluster_endpoint" {
  description = "Writer endpoint for the Aurora cluster"
  value       = aws_rds_cluster.aurora_cluster.endpoint
}

output "cluster_reader_endpoint" {
  description = "Reader endpoint for the Aurora cluster"
  value       = aws_rds_cluster.aurora_cluster.reader_endpoint
}

output "database_password" {
  description = "Database master password (sensitive)"
  value       = random_password.db_master_password.result
  sensitive   = true
}
```

