terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider for the primary region (us-east-2)
provider "aws" {
  region = "us-east-2"
}

# Provider for the replica region (us-west-2)
provider "aws" {
  alias  = "replica_west"
  region = "us-west-2"
}

resource "aws_dynamodb_table" "global_table" {
  provider = aws
  name           = "example-global-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  # Stream is required for Global Tables
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "id"
    type = "S"
  }

  # Define the replica in us-west-2
  # The table itself is created in us-east-2 (via the provider)
  replica {
    region_name = "us-west-2"
    # Explicitly point to the provider alias for the replica region
    provider = aws.replica_west
  }
}

