variable "cluster_name" {
  description = "Name of the DAX cluster"
  type        = string
  default     = "terraform-dax-cluster"
}

variable "vpc_id" {
  description = "VPC ID where DAX will be deployed"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs for the DAX subnet group"
  type        = list(string)
}

variable "node_type" {
  description = "Compute and memory capacity of the nodes"
  type        = string
  default     = "dax.t3.small"
}

variable "replication_factor" {
  description = "Number of nodes in the DAX cluster"
  type        = number
  default     = 1
}

resource "aws_iam_role" "dax_role" {
  name = "${var.cluster_name}-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "dax_policy" {
  name = "${var.cluster_name}-policy"
  role = aws_iam_role.dax_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "dynamodb:DescribeTable",
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:UpdateItem",
          "dynamodb:DeleteItem",
          "dynamodb:Query",
          "dynamodb:Scan"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_security_group" "dax_sg" {
  name        = "${var.cluster_name}-sg"
  description = "Security group for DAX cluster"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.cluster_name}-sg"
  }
}

resource "aws_dax_subnet_group" "main" {
  name       = "${var.cluster_name}-subnet-group"
  subnet_ids = var.subnet_ids
}

resource "aws_dax_parameter_group" "main" {
  name = "${var.cluster_name}-param-group"

  parameters {
    name  = "query-ttl-millis"
    value = "100000"
  }
}

resource "aws_dax_cluster" "main" {
  cluster_name              = var.cluster_name
  iam_role_arn              = aws_iam_role.dax_role.arn
  node_type                 = var.node_type
  replication_factor        = var.replication_factor
  subnet_group_name         = aws_dax_subnet_group.main.name
  security_group_ids        = [aws_security_group.dax_sg.id]
  parameter_group_name      = aws_dax_parameter_group.main.name

  tags = {
    Name = var.cluster_name
  }
}

output "dax_cluster_endpoint" {
  description = "The configuration endpoint for the DAX cluster"
  value       = aws_dax_cluster.main.configuration_endpoint
}

