provider "aws" {
  region = "us-east-1"
}

# VPC 1 (Requester)
resource "aws_vpc" "vpc_main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "vpc-main"
  }
}

# VPC 2 (Accepter)
resource "aws_vpc" "vpc_peer" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "vpc-peer"
  }
}

# VPC Peering Connection
resource "aws_vpc_peering_connection" "peer_conn" {
  vpc_id      = aws_vpc.vpc_main.id
  peer_vpc_id = aws_vpc.vpc_peer.id
  auto_accept = false

  tags = {
    Name = "vpc-peering-connection"
  }
}

# Accepter side configuration
resource "aws_vpc_peering_connection_accepter" "peer_accepter" {
  vpc_peering_connection_id = aws_vpc_peering_connection.peer_conn.id
  auto_accept               = true

  tags = {
    Name = "vpc-peering-accepter"
  }
}

# Route Table for Main VPC
resource "aws_route_table" "rt_main" {
  vpc_id = aws_vpc.vpc_main.id

  tags = {
    Name = "rt-main"
  }
}

# Route Table for Peer VPC
resource "aws_route_table" "rt_peer" {
  vpc_id = aws_vpc.vpc_peer.id

  tags = {
    Name = "rt-peer"
  }
}

# Route from Main to Peer
resource "aws_route" "route_to_peer" {
  route_table_id         = aws_route_table.rt_main.id
  destination_cidr_block = aws_vpc.vpc_peer.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.peer_conn.id
}

# Route from Peer to Main
resource "aws_route" "route_to_main" {
  route_table_id         = aws_route_table.rt_peer.id
  destination_cidr_block = aws_vpc.vpc_main.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.peer_conn.id
}

