    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Custom Neptune Parameter Group
resource "aws_neptune_parameter_group" "custom" {
  name        = "neptune-custom-parameter-group"
  description = "Custom parameter group for Neptune"
  family      = "neptune1"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }
}

# 2. VPC and Networking
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

# Subnet 1
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "neptune-subnet-1"
  }
}

# Subnet 2
resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-2"
  }
}

# 3. DB Subnet Group (Neptune requires at least 2 subnets in different AZs)
resource "aws_db_subnet_group" "neptune" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "My Neptune Subnet Group"
  }
}

# 4. Security Group (Restricts access to the two specific subnets)
resource "aws_security_group" "neptune" {
  name        = "neptune-security-group"
  description = "Allow Neptune inbound traffic only from specific subnets"
  vpc_id      = aws_vpc.main.id

  # Ingress rule: Allow access on port 8182 (Neptune default) only from the two defined subnets
  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet_1.cidr_block, aws_subnet.subnet_2.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# 5. Neptune Cluster
resource "aws_neptune_cluster" "main" {
  cluster_identifier              = "neptune-cluster-demo"
  engine                          = "neptune"
  engine_version                  = "1.2.1.0"
  backup_retention_period         = 5
  preferred_backup_window         = "07:00-09:00"
  skip_final_snapshot             = true
  apply_immediately               = true
  neptune_cluster_parameter_group_name = aws_neptune_parameter_group.custom.name
  db_subnet_group_name            = aws_db_subnet_group.neptune.name
  vpc_security_group_ids          = [aws_security_group.neptune.id]

  tags = {
    Name = "neptune-cluster"
  }
}

# 6. Neptune Cluster Instance (Writer)
resource "aws_neptune_cluster_instance" "main" {
  count              = 1
  identifier         = "neptune-instance-writer"
  cluster_identifier = aws_neptune_cluster.main.id
  engine             = "neptune"
  instance_class     = "db.t4g.medium"
  apply_immediately  = true
  publicly_accessible = false
}

