  engine_version                      = "1.2.1.0.R20240229"
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom_cluster_pg.name
  skip_final_snapshot                 = true
  backup_retention_period             = 5
  vpc_security_group_ids              = [aws_security_group.neptune_sg.id]
  db_subnet_group_name                = aws_db_subnet_group.neptune_subnet_group.name

  tags = {
    Name = "neptune-example-cluster"
  }
}

# Neptune Instance
resource "aws_neptune_cluster_instance" "example" {
