provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# Variables
# -----------------------------------------------------------------------------
variable "cluster_identifier" {
  description = "The identifier for the Redshift cluster"
  default     = "tf-redshift-cluster"
}

variable "database_name" {
  description = "The name of the default database in the cluster"
  default     = "dev"
}

variable "master_username" {
  description = "Username for the master user"
  default     = "admin"
}

variable "master_password" {
  description = "Password for the master user"
  sensitive   = true
}

variable "notification_email" {
  description = "Email address to receive event notifications"
  type        = string
}

# -----------------------------------------------------------------------------
# Data Sources (VPC and Subnets)
# -----------------------------------------------------------------------------
data "aws_vpc" "default" {
  default = true
}

data "aws_subnet_ids" "default" {
  vpc_id = data.aws_vpc.default.id
}

# -----------------------------------------------------------------------------
# Security Group
# -----------------------------------------------------------------------------
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic for Redshift"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "tf-redshift-sg"
  }
}

# -----------------------------------------------------------------------------
# Redshift Subnet Group
# -----------------------------------------------------------------------------
resource "aws_redshift_subnet_group" "default" {
  name       = "tf-redshift-subnet-group"
  subnet_ids = data.aws_subnet_ids.default.ids

  tags = {
    Name = "My Redshift Subnet Group"
  }
}

# -----------------------------------------------------------------------------
# SNS Topic for Notifications
# -----------------------------------------------------------------------------
resource "aws_sns_topic" "redshift_alerts" {
  name = "redshift-event-notifications"
}

resource "aws_sns_topic_subscription" "email_alert" {
  topic_arn = aws_sns_topic.redshift_alerts.arn
  protocol  = "email"
  endpoint  = var.notification_email
}

# -----------------------------------------------------------------------------
# Redshift Event Subscription
# -----------------------------------------------------------------------------
resource "aws_redshift_event_subscription" "default" {
  name          = "tf-redshift-event-sub"
  sns_topic_arn = aws_sns_topic.redshift_alerts.arn
  source_type   = "cluster"
  source_ids    = [aws_redshift_cluster.default.cluster_identifier]

  # Subscribe to all event categories (configuration, management, monitoring, security)
  # You can specify specific categories if needed
  event_categories = [
    "configuration",
    "management",
    "monitoring",
    "security"
  ]

  depends_on = [aws_redshift_cluster.default]
}

# -----------------------------------------------------------------------------
# Redshift Cluster
# -----------------------------------------------------------------------------
resource "aws_redshift_cluster" "default" {
  cluster_identifier  = var.cluster_identifier
  database_name       = var.database_name
  master_username     = var.master_username
  master_password     = var.master_password
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
  publicly_accessible = true
  skip_final_snapshot = true

  tags = {
    Environment = "Terraform-Test"
  }
}

