provider "aws" {
  region = "us-east-1"
}

# SNS Topic for receiving event notifications
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-parameter-group-notifications"
}

# Redshift Parameter Group with example parameters
resource "aws_redshift_parameter_group" "example" {
  name   = "example-parameter-group"
  family = "redshift-1.0"

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "max_concurrency_scaling_clusters"
    value = "2"
  }

  parameter {
    name  = "require_ssl"
    value = "true"
  }

  tags = {
    Name = "example-parameter-group"
  }
}

# Event Subscription for Parameter Group events
resource "aws_redshift_event_subscription" "example" {
  name          = "redshift-pg-event-subscription"
  sns_topic_arn = aws_sns_topic.redshift_notifications.arn

  # Subscribe to events specifically for the parameter group
  source_type = "parameter-group"

  # Event categories to monitor
  event_categories = [
    "configuration-change",
    "management"
  ]

  # Link to the specific parameter group ID
  source_ids = [
    aws_redshift_parameter_group.example.name
  ]

  tags = {
    Name = "pg-event-subscription"
  }
}

