provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "pdf_bucket" {
  bucket = "my-unique-pdf-assets-bucket"
}

resource "aws_s3_bucket_ownership_controls" "pdf_bucket_ownership" {
  bucket = aws_s3_bucket.pdf_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "pdf_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.pdf_bucket_ownership]

  bucket = aws_s3_bucket.pdf_bucket.id
  acl    = "private"
}

resource "aws_s3_object" "pdf_upload" {
  bucket = aws_s3_bucket.pdf_bucket.id
  key    = "test.pdf"
  source = "assets/test.pdf"
  etag   = filemd5("assets/test.pdf")

  # Ensure the ACL matches the bucket ownership settings
  acl = "private"
}
