extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# ---------------------------------------------------------
# Variables
# ---------------------------------------------------------

variable "aws_region" {
  description = "AWS Region where resources will be created"
  default     = "us-east-1"
}

variable "github_repo_url" {
  description = "The HTTPS URL of the GitHub repository (e.g., https://github.com/user/repo)"
  type        = string
}

variable "codestar_connection_arn" {
  description = "The ARN of the AWS CodeStar connection used to authenticate with GitHub"
  type        = string
}

variable "environment_image" {
  description = "The Docker image to use for the grading environment"
  default     = "aws/codebuild/standard:6.0"
}

variable "project_name" {
  description = "Name of the CodeBuild project"
  default     = "cs-autograder"
}

# ---------------------------------------------------------
# S3 Bucket for Grading Results
# ---------------------------------------------------------

resource "aws_s3_bucket" "autograder_results" {
  bucket = "${var.project_name}-results-${random_pet.suffix.id}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# ---------------------------------------------------------
# IAM Role for CodeBuild
# ---------------------------------------------------------

data "aws_iam_policy_document" "codebuild_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "codebuild_role" {
  name = "${var.project_name}-role"
  assume_role_policy = data.aws_iam_policy_document.codebuild_assume_role.json
}

data "aws_iam_policy_document" "codebuild_policy" {
  statement {
    effect = "Allow"

    actions = [
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["*"]
  }

  statement {
    effect = "Allow"

    actions = [
      "s3:GetBucketAcl",
      "s3:GetBucketLocation",
      "s3:GetObject",
      "s3:GetObjectAcl",
      "s3:ListBucket",
      "s3:PutObject",
      "s3:PutObjectAcl",
    ]

    resources = [
      aws_s3_bucket.autograder_results.arn,
      "${aws_s3_bucket.autograder_results.arn}/*",
    ]
  }
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role   = aws_iam_role.codebuild_role.name
  policy = data.aws_iam_policy_document.codebuild_policy.json
}

# ---------------------------------------------------------
# CodeBuild Project
# ---------------------------------------------------------

resource "aws_codebuild_project" "autograder" {
  name         = var.project_name
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Store grading results (logs/output) in S3 via secondary artifacts or specific buildspec commands
  secondary_artifacts {
    type            = "S3"
    location        = aws_s3_bucket.autograder_results.bucket
    artifact_identifier = "grading-results"
    path            = "results/"
    name            = "results.zip"
    packaging       = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = var.environment_image
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repo_url
    git_clone_depth = 1

    buildspec = <<-EOF
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.9
          commands:
            - echo "Installing grading dependencies..."
            # - pip install -r requirements_grader.txt
        pre_build:
          commands:
            - echo "Preparing environment..."
        build:
          commands:
            - echo "Running autograder..."
            # Logic to run student tests. Example:
            - python run_tests.py > grading_report.json
            - echo "Build finished."
        post_build:
          commands:
            - echo "Uploading results to S3 artifact..."
            - mkdir results
            - cp grading_report.json results/
      artifacts:
        secondary-artifacts:
          grading-results:
            base-directory: results
            files:
              - '**/*'
    EOF
  }

  source_version = "main" # Default branch

  # Optional: Trigger build on webhook
  # triggers {
  #   webhook = true
  # }
}

# ---------------------------------------------------------
# Random Suffix for unique naming
# ---------------------------------------------------------

resource "random_pet" "suffix" {
  length = 2
}

