resource "aws_codebuild_project" "autograder" {
  name          = var.project_name
  description   = "Autograder project for CS class"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "30"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_results.id
    name = "grading-results"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = var.environment_image
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    # You can define environment variables here for your autograder scripts
    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.id
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/${var.project_name}"
      stream_name = "build-logs"
    }
  }

  source {
    type                = "GITHUB"
    location            = var.github_repo_url
    git_clone_depth     = 1

    # Report build status back to GitHub
    report_build_status = true
  }

  source_version = "main" # Default branch to build
}

