resource "aws_iam_role_policy_attachment" "codebuild_base_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildDeveloperAccess"
}

# Custom Policy for S3 Access and Logging
resource "aws_iam_role_policy" "codebuild_custom_policy" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "logs:CreateLogGroup",
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": "*"
    },
    {
      "Effect": "Allow",
      "Action": [
        "s3:PutObject",
        "s3:GetObject",
        "s3:GetObjectVersion"
      ],
      "Resource": "${aws_s3_bucket.results_bucket.arn}/*"
    }
  ]
}
EOF
}

# CodeBuild Project
variable "github_repo_url" {
  description = "The HTTPS URL of the GitHub repository (e.g., https://github.com/user/repo)"
  type        = string
}

variable "github_oauth_token" {
  description = "GitHub Personal Access Token (PAT) or OAuth token for accessing the repository"
  type        = string
  sensitive   = true
}

resource "aws_codebuild_project" "autograder_project" {
  name          = "autograder-${random_string.suffix.result}"
  description   = "Runs student code and uploads results to S3"
  build_timeout = "15"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:6.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.results_bucket.bucket
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_log_group.name
      stream_name = "autograder-build"
    }
  }

  source {
    type     = "GITHUB"
    location = var.github_repo_url
    git_clone_depth = 1

    auth {
      type     = "OAUTH"
      resource = var.github_oauth_token
    }
  }

  source_version = "main"

  # Inline Buildspec
  buildspec = <<EOF
version: 0.2

phases:
  install:
    runtime-versions:
      python: 3.9
      java: corretto11
    commands:
      - echo "Installing dependencies..."
      # Add installation commands here (e.g., pip install -r requirements.txt, mvn install)

  pre_build:
    commands:
      - echo "Running pre-build setup..."

  build:
    commands:
      - echo "Running Autograder Tests..."
      # Add command to run tests (e.g., python test_runner.py or mvn test)
      - echo "Simulating test run..."
      - echo '{"status": "passed", "score": 100}' > results.json

  post_build:
    commands:
      - echo "Uploading results to S3..."
      - aws s3 cp results.json s3://$RESULTS_BUCKET/$(date +%Y-%m-%d-%H-%M-%S)-results.json
      - echo "Build completed."
EOF
}

