extracted_code:
# This configuration creates an isolated environment for an autograder using AWS CodeBuild.
# To satisfy the requirement of preventing student code from reaching the internet while
# running code from GitHub, this setup assumes a "S3 Proxy" pattern where a GitHub Webhook
# triggers a Lambda (not shown) to sync code to an S3 bucket. CodeBuild then runs in an
# isolated VPC with no internet access, pulling artifacts strictly from S3 via VPC Endpoints.

provider "aws" {
  region = "us-east-1"
}

# 1. Networking: VPC and Private Subnets
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "autograder-vpc"
  }
}

resource "aws_subnet" "private_subnets" {
  count             = 2
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "autograder-subnet-${count.index + 1}"
  }
}

# Isolated Route Table (No IGW or NAT Gateway routes)
resource "aws_route_table" "isolated" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "isolated-rt"
  }
}

resource "aws_route_table_association" "private" {
  count          = 2
  subnet_id      = aws_subnet.private_subnets[count.index].id
  route_table_id = aws_route_table.isolated.id
}

data "aws_availability_zones" "available" {}

# 2. VPC Endpoints for Private Access
# Gateway Endpoint for S3 (Source code and Artifacts)
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.${data.aws_region.current.name}.s3"

  tags = {
    Name = "s3-endpoint"
  }
}

resource "aws_vpc_endpoint_route_table_association" "s3" {
  route_table_id  = aws_route_table.isolated.id
  vpc_endpoint_id = aws_vpc_endpoint.s3.id
}

# Interface Endpoints for CodeBuild, CloudWatch, ECR, KMS, and Secrets Manager
# These allow the build environment to function without internet access.
resource "aws_vpc_endpoint" "codebuild" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private_subnets[*].id
  private_dns_enabled = true

  security_group_ids = [aws_security_group.vpc_endpoint.id]
}

resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private_subnets[*].id
  private_dns_enabled = true

  security_group_ids = [aws_security_group.vpc_endpoint.id]
}

resource "aws_vpc_endpoint" "ecr_api" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.ecr.api"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private_subnets[*].id
  private_dns_enabled = true

  security_group_ids = [aws_security_group.vpc_endpoint.id]
}

resource "aws_vpc_endpoint" "ecr_dkr" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.ecr.dkr"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private_subnets[*].id
  private_dns_enabled = true

  security_group_ids = [aws_security_group.vpc_endpoint.id]
}

resource "aws_vpc_endpoint" "kms" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.kms"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private_subnets[*].id
  private_dns_enabled = true

  security_group_ids = [aws_security_group.vpc_endpoint.id]
}

resource "aws_vpc_endpoint" "secretsmanager" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.secretsmanager"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private_subnets[*].id
  private_dns_enabled = true

  security_group_ids = [aws_security_group.vpc_endpoint.id]
}

# Security Group for VPC Endpoints
resource "aws_security_group" "vpc_endpoint" {
  name        = "vpc-endpoint-sg"
  description = "Security group for VPC Interface Endpoints"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Security Group for CodeBuild
# Allows only internal communication. 
# Internet access is blocked by the lack of a NAT Gateway/IGW route.
resource "aws_security_group" "codebuild" {
  name        = "autograder-codebuild-sg"
  description = "Security group for CodeBuild in isolated VPC"
  vpc_id      = aws_vpc.autograder_vpc.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"] # Allowed, but internet is unreachable via Route Table
  }
}

# 4. IAM Role for CodeBuild
data "aws_iam_policy_document" "assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "codebuild_role" {
  name               = "autograder-codebuild-role"
  assume_role_policy = data.aws_iam_policy_document.assume_role.json
}

resource "aws_iam_role_policy_attachment" "codebuild_base" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildDeveloperAccess"
}

# Custom policy for specific S3 and Logs access (more secure than full admin)
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketVersioning"
        ]
        Resource = [
          "arn:aws:s3:::autograder-submissions/*",
          "arn:aws:s3:::autograder-submissions"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ]
        Resource = "*"
      }
    ]
  })
}

# 5. CodeBuild Project
# Note: Source type is S3. To integrate with GitHub, use a webhook -> Lambda -> S3 flow.
resource "aws_codebuild_project" "autograder" {
  name          = "cs-class-autograder"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "10"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:6.0"
    type         = "LINUX_CONTAINER"

    # Privileged mode is often needed for Docker-based autograders
    privileged_mode = true

    environment_variable {
      name  = "OUTPUT_BUCKET"
      value = "autograder-results"
    }
  }

  source {
    type            = "S3"
    location        = "autograder-submissions/student-submission.zip" # Example location
    buildspec       = "buildspec.yml"
  }

  # VPC Configuration enforces isolation
  vpc_config {
    vpc_id = aws_vpc.autograder_vpc.id

    subnets = [
      aws_subnet.private_subnets[0].id,
      aws_subnet.private_subnets[1].id
    ]

    security_group_ids = [
      aws_security_group.codebuild.id
    ]
  }

  logs_config {
    cloudwatch_logs {
      group_name = "autograder-logs"
      stream_name = "build-logs"
    }
  }
}

