```hcl
provider "aws" {
  region = "us-east-1"
}

# Data source to fetch GitHub's public IP ranges dynamically to restrict outbound access
data "http" "github_meta" {
  url = "https://api.github.com/meta"
}

locals {
  # Parse the JSON response to get GitHub Hook IPs (Webhooks/Requests)
  github_cidr_blocks = jsondecode(data.http.github_meta.response_body).hooks
}

# --- VPC and Networking ---

resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Public Subnet (for NAT Gateway)
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.autograder_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "autograder-public-subnet"
  }
}

# Private Subnet (for CodeBuild)
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-private-subnet"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-igw"
  }
}

# NAT Gateway (Required to fetch code from GitHub)
resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "autograder-nat"
  }

  depends_on = [aws_internet_gateway.igw]
}

# Route Tables
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "autograder-public-rt"
  }
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# --- VPC Endpoints (Securely access AWS services without Internet/NAT) ---

# Gateway Endpoint for S3 (Free, secure access to S3)
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"

  route_table_ids = [aws_route_table.private.id]

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

# Interface Endpoint for CodeBuild (Allows CodeBuild to communicate with control plane)
resource "aws_vpc_endpoint" "codebuild" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.us-east-1.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private.id]
  private_dns_enabled = true

  security_group_ids = [aws_security_group.vpc_endpoint.id]

  tags = {
    Name = "autograder-codebuild-endpoint"
  }
}

# Interface Endpoint for CloudWatch Logs (For logging without internet)
resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.us-east-1.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private.id]
  private_dns_enabled = true

  security_group_ids = [aws_security_group.vpc_endpoint.id]

  tags = {
    Name = "autograder-logs-endpoint"
  }
}

# --- Security Groups ---

# Security Group for VPC Endpoints (Allows traffic from CodeBuild)
resource "aws_security_group" "vpc_endpoint" {
  name        = "vpc-endpoint-sg"
  description = "Security group for VPC Interface Endpoints"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Security Group for CodeBuild (Restricts Outbound Access)
resource "aws_security_group" "codebuild" {
  name        = "autograder-codebuild-sg"
  description = "Restricts student code internet access. Allows GitHub and VPC Internal only."
  vpc_id      = aws_vpc.autograder_vpc.id

  egress {
    description = "Allow HTTPS to GitHub (for source fetching)"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = local.github_cidr_blocks
  }

  egress {
    description = "Allow all traffic within VPC (for VPC Endpoints)"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  # Deny all other outbound traffic is implicit in SGs (deny all), 
  # but we explicitly allow ONLY GitHub and VPC above.
}

# --- S3 Bucket for Results ---

resource "aws_s3_bucket" "results_bucket" {
  bucket = "autograder-results-bucket-unique-id-12345"

  tags = {
    Name = "autograder-results"
  }
}

resource "aws_s3_bucket_versioning" "results_versioning" {
  bucket = aws_s3_bucket.results_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# --- IAM Roles ---

resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "codebuild.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_policy" "codebuild_policy" {
  name        = "autograder-codebuild-policy"
  description = "Policy for CodeBuild to access S3, CloudWatch, and VPC"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "logs:CreateLogGroup",
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": "arn:aws:logs:*:*:*"
    },
    {
      "Effect": "Allow",
      "Action": [
        "s3:GetObject",
        "s3:PutObject",
        "s3:ListBucket"
      ],
      "Resource": [
        "${aws_s3_bucket.results_bucket.arn}",
        "${aws_s3_bucket.results_bucket.arn}/*"
      ]
    },
    {
      "Effect": "Allow",
      "Action": [
        "codebuild:CreateReportGroup",
        "codebuild:CreateReport",
        "codebuild:UpdateReport",
        "codebuild:BatchPutTestCases",
        "codebuild:BatchPutCodeCoverages"
      ],
      "Resource": "*"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "codebuild_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# --- CodeBuild Project ---

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Runs student code from GitHub in a restricted VPC environment"
  build_timeout = "10"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    # Pass the bucket name as environment variable
    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.results_bucket.id
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/your-repo.git" # Replace with actual repo
    git_clone_depth = 1
  }

  # VPC Configuration for Network Isolation
  vpc_config {
    vpc_id = aws_vpc.autograder_vpc.id

    subnets = [
      aws_subnet.private.id
    ]

    security_group_ids = [
      aws_security_group.codebuild.id
    ]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-build-logs"
      stream_name = "build-logs"
    }
  }
}
