provider "aws" {
  region = "us-east-1"
}

# Random ID for unique naming
resource "random_id" "this" {
  byte_length = 4
}

# --- VPC and Networking ---

resource "aws_vpc" "this" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "autograder-vpc-${random_id.this.hex}"
  }
}

# Public Subnet for NAT Gateway
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.this.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "autograder-public-subnet-${random_id.this.hex}"
  }
}

# Private Subnet for CodeBuild
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.this.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "autograder-private-subnet-${random_id.this.hex}"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "this" {
  vpc_id = aws_vpc.this.id

  tags = {
    Name = "autograder-igw-${random_id.this.hex}"
  }
}

# Elastic IP for NAT Gateway
resource "aws_eip" "nat" {
  domain = "vpc"

  tags = {
    Name = "autograder-nat-eip-${random_id.this.hex}"
  }
}

# NAT Gateway (Required for CodeBuild to fetch GitHub source and Docker images)
resource "aws_nat_gateway" "this" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "autograder-nat-${random_id.this.hex}"
  }
}

# Route Table (Public)
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.this.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.this.id
  }

  tags = {
    Name = "autograder-public-rt-${random_id.this.hex}"
  }
}

# Route Table (Private) -> Routes internet traffic through NAT
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.this.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.this.id
  }

  tags = {
    Name = "autograder-private-rt-${random_id.this.hex}"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# --- VPC Endpoints for Isolation ---

# Gateway Endpoint for S3 (Ensures build artifacts/logs do not traverse public internet)
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.this.id
  service_name = "com.amazonaws.${var.aws_region}.s3"
  route_table_ids = [
    aws_route_table.private.id
  ]

  tags = {
    Name = "autograder-s3-endpoint-${random_id.this.hex}"
  }
}

# Interface Endpoint for CloudWatch Logs (Ensures logs do not traverse public internet)
resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.this.id
  service_name        = "com.amazonaws.${var.aws_region}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private.id]
  private_dns_enabled = true

  security_group_ids = [aws_security_group.vpc_endpoint.id]

  tags = {
    Name = "autograder-logs-endpoint-${random_id.this.hex}"
  }
}

# --- Security Groups ---

resource "aws_security_group" "codebuild" {
  name        = "autograder-codebuild-sg-${random_id.this.hex}"
  description = "Security group for CodeBuild in VPC"
  vpc_id      = aws_vpc.this.id

  # Egress only to specific ports needed
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Necessary for GitHub and Docker Hub access
  }

  # Egress for S3 via VPC Endpoint (if needed, though Gateway endpoint handles routing)
  # Egress for interface endpoints
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  tags = {
    Name = "autograder-codebuild-sg-${random_id.this.hex}"
  }
}

resource "aws_security_group" "vpc_endpoint" {
  name        = "autograder-vpc-endpoint-sg-${random_id.this.hex}"
  description = "Security group for VPC Interface Endpoints"
  vpc_id      = aws_vpc.this.id

  ingress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.codebuild.id]
  }

  tags = {
    Name = "autograder-vpc-endpoint-sg-${random_id.this.hex}"
  }
}

# --- Storage ---

resource "aws_s3_bucket" "results" {
  bucket = "autograder-results-${random_id.this.hex}"

  tags = {
    Name = "autograder-results-${random_id.this.hex}"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "results" {
  bucket = aws_s3_bucket.results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_versioning" "results" {
  bucket = aws_s3_bucket.results.id
  versioning_configuration {
    status = "Enabled"
  }
}

# --- IAM ---

resource "aws_iam_role" "codebuild" {
  name = "autograder-codebuild-role-${random_id.this.hex}"

  assume_role_policy = <<EOF
{
