data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "lambda_function_payload.zip"
  source {
    content = <<EOF
import json
import boto3
import random
import os

s3 = boto3.client('s3')
BUCKET_NAME = os.environ['BUCKET_NAME']

def lambda_handler(event, context):
    http_method = event.get('httpMethod')
    path = event.get('path')

    # GET /random - Returns a random cat picture URL
    if http_method == 'GET' and path == '/random':
        try:
            response = s3.list_objects_v2(Bucket=BUCKET_NAME)
            if 'Contents' not in response or not response['Contents']:
                return {
                    'statusCode': 404,
                    'body': json.dumps({'message': 'No cat pictures found. Please upload one first!'})
                }

            # Pick a random file
            files = response['Contents']
            random_file = random.choice(files)
            key = random_file['Key']

            # Generate Pre-signed URL for reading
            url = s3.generate_presigned_url(
                'get_object',
                Params={'Bucket': BUCKET_NAME, 'Key': key},
                ExpiresIn=3600
            )

            return {
                'statusCode': 200,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({'url': url, 'filename': key})
            }
        except Exception as e:
            return {'statusCode': 500, 'body': json.dumps({'error': str(e)})}

    # POST /upload - Returns a pre-signed URL to upload a picture
    elif http_method == 'POST' and path == '/upload':
        try:
            # Generate a unique key name
            filename = f"cat_{random.randint(1000,9999)}.jpg"

            # Generate Pre-signed URL for uploading
            url = s3.generate_presigned_url(
                'put_object',
                Params={'Bucket': BUCKET_NAME, 'Key': filename, 'ContentType': 'image/jpeg'},
                ExpiresIn=3600
            )

            return {
                'statusCode': 200,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({'upload_url': url, 'filename': filename})
            }
        except Exception as e:
            return {'statusCode': 500, 'body': json.dumps({'error': str(e)})}

    return {'statusCode': 400, 'body': json.dumps({'message': 'Invalid endpoint'})}
EOF
    filename = "index.py"
  }
}

resource "aws_lambda_function" "cat_api" {
