data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "cat_service_lambda.zip"
  source {
    content = <<EOF
import json
import boto3
import base64
import random
import os

s3_client = boto3.client('s3')
BUCKET_NAME = os.environ['BUCKET_NAME']

def lambda_handler(event, context):
    path = event.get('path', '')
    method = event.get('httpMethod', '')

    # Handle POST /upload
    if path == '/upload' and method == 'POST':
        try:
            body = json.loads(event['body'])
            image_data = body.get('image') # Expecting Base64 string
            filename = body.get('filename', f'cat_{random.randint(1000,9999)}.jpg')

            # Decode and Upload
            image_bytes = base64.b64decode(image_data)
            s3_client.put_object(Bucket=BUCKET_NAME, Key=filename, Body=image_bytes, ContentType='image/jpeg')

            return {
                'statusCode': 200,
                'body': json.dumps({'message': 'Upload successful', 'filename': filename})
            }
        except Exception as e:
            return {
                'statusCode': 500,
                'body': json.dumps({'error': str(e)})
            }

    # Handle GET /random
    elif path == '/random' and method == 'GET':
        try:
            response = s3_client.list_objects_v2(Bucket=BUCKET_NAME)
            if 'Contents' not in response or not response['Contents']:
                return {
                    'statusCode': 404,
                    'body': json.dumps({'error': 'No pictures found'})
                }

            # Select random object
            obj = random.choice(response['Contents'])
            key = obj['Key']

            # Generate Presigned URL (valid for 1 hour)
            url = s3_client.generate_presigned_url('get_object', Params={'Bucket': BUCKET_NAME, 'Key': key}, ExpiresIn=3600)

            return {
                'statusCode': 200,
                'body': json.dumps({'url': url})
            }
        except Exception as e:
            return {
                'statusCode': 500,
                'body': json.dumps({'error': str(e)})
            }

    return {
        'statusCode': 400,
        'body': json.dumps({'message': 'Bad Request'})
    }
EOF
    filename = "lambda_function.py"
  }
}

