# Generate the Lambda code locally
resource "local_file" "lambda_handler" {
  content  = <<EOF
import json
import boto3
import random
import base64
import os

s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table(os.environ['TABLE_NAME'])
bucket_name = os.environ['BUCKET_NAME']

def lambda_handler(event, context):
    # Handle Upload (POST)
    if event['httpMethod'] == 'POST':
        body = json.loads(event['body'])
        image_id = body.get('image_id')
        image_data = body.get('image_data') # Base64 encoded

        # Decode and Upload to S3
        decoded_data = base64.b64decode(image_data)
        s3_client.put_object(Bucket=bucket_name, Key=image_id, Body=decoded_data)

        # Save metadata to DynamoDB
        table.put_item(Item={'ImageId': image_id})

        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Cat picture uploaded!', 'id': image_id})
        }

    # Handle Get Random (GET)
    elif event['httpMethod'] == 'GET':
        # Scan DynamoDB for all image IDs
        response = table.scan()
        items = response.get('Items', [])

        if not items:
            return {'statusCode': 404, 'body': json.dumps({'message': 'No cats found'})}

        # Pick a random image
        random_item = random.choice(items)
        image_id = random_item['ImageId']

        # Generate a pre-signed URL (valid for 1 hour)
        url = s3_client.generate_presigned_url(
            'get_object',
            Params={'Bucket': bucket_name, 'Key': image_id},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'body': json.dumps({'image_url': url})
        }

    return {'statusCode': 400, 'body': json.dumps({'message': 'Unsupported method'})}
EOF
  filename = "${path.module}/lambda_function.py"
}

