provider "aws" {
  region = "us-east-1"
}

# S3 Bucket to store cat pictures
resource "aws_s3_bucket" "cat_pictures" {
  bucket = "cat-pictures-bucket-unique-id-123"
}

# DynamoDB Table to store metadata (e.g., image IDs)
resource "aws_dynamodb_table" "cat_metadata" {
  name           = "CatMetadata"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "ImageId"

  attribute {
    name = "ImageId"
    type = "S"
  }
}

# IAM Role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "cat_service_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# IAM Policy for Lambda to access S3 and DynamoDB
resource "aws_iam_role_policy" "lambda_policy" {
  name = "cat_service_lambda_policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject"
        ]
        Resource = "${aws_s3_bucket.cat_pictures.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:Scan"
        ]
        Resource = aws_dynamodb_table.cat_metadata.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Generate the Lambda code locally
resource "local_file" "lambda_handler" {
  content  = <<EOF
import json
import boto3
import random
import base64
import os

s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table(os.environ['TABLE_NAME'])
bucket_name = os.environ['BUCKET_NAME']

def lambda_handler(event, context):
    # Handle Upload (POST)
    if event['httpMethod'] == 'POST':
        body = json.loads(event['body'])
        image_id = body.get('image_id')
        image_data = body.get('image_data') # Base64 encoded

        # Decode and Upload to S3
        decoded_data = base64.b64decode(image_data)
        s3_client.put_object(Bucket=bucket_name, Key=image_id, Body=decoded_data)

        # Save metadata to DynamoDB
        table.put_item(Item={'ImageId': image_id})

        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Cat picture uploaded!', 'id': image_id})
        }

    # Handle Get Random (GET)
    elif event['httpMethod'] == 'GET':
        # Scan DynamoDB for all image IDs
        response = table.scan()
        items = response.get('Items', [])

        if not items:
            return {'statusCode': 404, 'body': json.dumps({'message': 'No cats found'})}

        # Pick a random image
        random_item = random.choice(items)
        image_id = random_item['ImageId']

        # Generate a pre-signed URL (valid for 1 hour)
        url = s3_client.generate_presigned_url(
            'get_object',
            Params={'Bucket': bucket_name, 'Key': image_id},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'body': json.dumps({'image_url': url})
        }

    return {'statusCode': 400, 'body': json.dumps({'message': 'Unsupported method'})}
EOF
  filename = "${path.module}/lambda_function.py"
}

# Zip the Lambda code
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_handler.filename
  output_path = "${path.module}/lambda_function_payload.zip"
}

# AWS Lambda Function
resource "aws_lambda_function" "cat_service" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "CatPictureService"
  role          = aws_iam_role.lambda_role.arn
  handler       = "lambda_function.lambda_handler"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  runtime = "python3.9"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pictures.id
      TABLE_NAME  = aws_dynamodb_table.cat_metadata.name
    }
  }
}

# API Gateway Rest API
