```hcl
# Provider Block
provider "aws" {
  region = "us-east-1"
}

# Data source for current region
data "aws_region" "current" {}

# ---------------------------------------------------------
# S3 Bucket for Cat Pictures
# ---------------------------------------------------------
resource "aws_s3_bucket" "cat_pictures" {
  bucket = "caas-cat-pictures-bucket"
}

resource "aws_s3_bucket_ownership_controls" "cat_pictures" {
  bucket = aws_s3_bucket.cat_pictures.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "cat_pictures" {
  depends_on = [aws_s3_bucket_ownership_controls.cat_pictures]
  bucket     = aws_s3_bucket.cat_pictures.id
  acl        = "private"
}

# ---------------------------------------------------------
# DynamoDB Table for Cat Metadata
# ---------------------------------------------------------
resource "aws_dynamodb_table" "cats" {
  name           = "CatsTable"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "name"

  attribute {
    name = "name"
    type = "S"
  }
}

# ---------------------------------------------------------
# IAM Role for Lambda Functions
# ---------------------------------------------------------
resource "aws_iam_role" "lambda_role" {
  name = "caas_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Policy to allow Lambda to access logs, S3, and DynamoDB
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_access" {
  name = "caas_lambda_access_policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "dynamodb:GetItem",
          "dynamodb:PutItem",
          "dynamodb:Scan"
        ]
        Resource = aws_dynamodb_table.cats.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = "${aws_s3_bucket.cat_pictures.arn}/*"
      }
    ]
  })
}

# ---------------------------------------------------------
# Helper to create dummy Lambda zip files
# ---------------------------------------------------------
resource "null_resource" "lambda_get_src" {
  triggers = {
    build = timestamp()
  }
  provisioner "local-exec" {
    command = "echo 'def handler(event, context): return {"statusCode": 200, "body": "Get Cat"}' > handler_get.py"
  }
}

data "archive_file" "lambda_get_zip" {
  type        = "zip"
  source_file = "handler_get.py"
  output_path = "lambda_get_payload.zip"
  depends_on  = [null_resource.lambda_get_src]
}

resource "null_resource" "lambda_put_src" {
  triggers = {
    build = timestamp()
  }
  provisioner "local-exec" {
    command = "echo 'def handler(event, context): return {"statusCode": 200, "body": "Put Cat"}' > handler_put.py"
  }
}

data "archive_file" "lambda_put_zip" {
  type        = "zip"
  source_file = "handler_put.py"
  output_path = "lambda_put_payload.zip"
  depends_on  = [null_resource.lambda_put_src]
}

# ---------------------------------------------------------
# Lambda Function: caas_get
# ---------------------------------------------------------
resource "aws_lambda_function" "get_cat" {
  filename      = "lambda_get_payload.zip"
  function_name = "caas_get"
  role          = aws_iam_role.lambda_role.arn
  handler       = "handler_get.handler"

  source_code_hash = data.archive_file.lambda_get_zip.output_base64sha256
  runtime          = "python3.9"
}

# ---------------------------------------------------------
# Lambda Function: caas_put
# ---------------------------------------------------------
resource "aws_lambda_function" "put_cat" {
  filename      = "lambda_put_payload.zip"
  function_name = "caas_put"
  role          = aws_iam_role.lambda_role.arn
  handler       = "handler_put.handler"

  source_code_hash = data.archive_file.lambda_put_zip.output_base64sha256
  runtime          = "python3.9"
}

# ---------------------------------------------------------
# API Gateway
# ---------------------------------------------------------
resource "aws_api_gateway_rest_api" "caas" {
  name        = "caas"
  description = "Cats as a Service API"
}

resource "aws_api_gateway_resource" "caas_cat" {
  parent_id   = aws_api_gateway_rest_api.caas.root_resource_id
  path_part   = "cat"
  rest_api_id = aws_api_gateway_rest_api.caas.id
}

# ---------------------------------------------------------
# API Gateway Method: GET
# ---------------------------------------------------------
resource "aws_api_gateway_method" "caas_get" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "caas_get" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  resource_id = aws_api_gateway_resource.caas_cat.id
  http_method = aws_api_gateway_method.caas_get.http_method

  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.get_cat.invoke_arn
}

# Permission for API Gateway to invoke GET Lambda
resource "aws_lambda_permission" "api_get_invoke" {
  statement_id  = "AllowAPIGatewayInvokeGet"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.get_cat.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.caas.execution_arn}/*/*"
}

# ---------------------------------------------------------
# API Gateway Method: PUT
# ---------------------------------------------------------
resource "aws_api_gateway_method" "caas_put" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "PUT"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "caas_put" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  resource_id = aws_api_gateway_resource.caas_cat.id
  http_method = aws_api_gateway_method.caas_put.http_method

  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.put_cat.invoke_arn
}

# Permission for API Gateway to invoke PUT Lambda
resource "aws_lambda_permission" "api_put_invoke" {
  statement_id  = "AllowAPIGatewayInvokePut"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.put_cat.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.caas.execution_arn}/*/*"
}

# ---------------------------------------------------------
# API Gateway Deployment
# ---------------------------------------------------------
resource "aws_api_gateway_deployment" "caas_deploy" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  triggers = {
    redployment = sha1(jsonencode([
      aws_api_gateway_resource.caas_cat.id,
      aws_api_gateway_method.caas_get.id,
      aws_api_gateway_method.caas_put.id,
      aws_api_gateway_integration.caas_get.id,
      aws_api_gateway_integration.caas_put.id
    ]))
  }
}

resource "aws_api_gateway_stage" "caas_stage" {
  deployment_id = aws_api_gateway_deployment.caas_deploy.id
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  stage_name    = "v1"
}
