provider "aws" {
  region = "us-east-1"
}

# Data source to fetch the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# Create the EC2 Instance
resource "aws_instance" "web_server" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"

  tags = {
    Name = "WebServer-BackedUp"
  }
}

# IAM Role required by AWS Backup to manage the backup jobs
resource "aws_iam_role" "backup_role" {
  name = "aws_backup_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the managed policy for backups to the role
resource "aws_iam_role_policy_attachment" "backup_attach" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

# Create a Backup Vault to store the backups
resource "aws_backup_vault" "web_server_vault" {
  name = "web-server-vault"
}

# Create the Backup Plan
resource "aws_backup_plan" "daily_midnight_plan" {
  name = "daily-midnight-plan"

  rule {
    rule_name         = "daily_midnight_rule"
    target_vault_arn  = aws_backup_vault.web_server_vault.arn
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 30
    }
  }
}

# Create a Backup Selection to assign the EC2 instance to the plan
