extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your preferred region
}

# Create a zip file for the Lambda function code inline
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function_payload.zip"

  source {
    content  = <<-EOF
      def handler(event, context):
          print("Running code every day at 7 UTC!")
          return {"statusCode": 200, "body": "Success"}
    EOF
    filename = "index.py"
  }
}

# IAM Role for Lambda Execution
resource "aws_iam_role" "lambda_role" {
  name = "daily_lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic execution policy to the role
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# The Lambda Function (The code to be run)
resource "aws_lambda_function" "daily_function" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "daily_7_utc_function"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.9"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
}

# EventBridge Rule (The Schedule: Every day at 7 UTC)
resource "aws_cloudwatch_event_rule" "daily_schedule" {
  name                = "daily-7-utc-rule"
  description         = "Triggers Lambda every day at 7 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# EventBridge Target (Connects the Rule to the Lambda)
resource "aws_cloudwatch_event_target" "daily_lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_schedule.name
  target_id = "DailyLambdaTarget"
  arn       = aws_lambda_function.daily_function.arn
}

# Permission for EventBridge to invoke the Lambda
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.daily_function.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_schedule.arn
}

