extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# Generate a random password for the database master user
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!%@"
}

# Create a KMS Key for encryption
resource "aws_kms_key" "rds_kms_key" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-postgres-kms-key"
  }
}

# Create an alias for the KMS Key to make identification easier
resource "aws_kms_alias" "rds_kms_alias" {
  name          = "alias/rds-postgres-key"
  target_key_id = aws_kms_key.rds_kms_key.key_id
}

# Create a DB Subnet Group within the specified VPC
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = var.private_subnet_ids

  tags = {
    Name = "PostgreSQL Subnet Group"
  }
}

# Create a Security Group to manage access
resource "aws_security_group" "postgres_sg" {
  name        = "postgres-security-group"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL access from specific CIDR"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "PostgreSQL SG"
  }
}

# Create a custom Parameter Group for PostgreSQL
resource "aws_db_parameter_group" "postgres_parameter_group" {
  name        = "custom-postgres-param-group"
  family      = "postgres14"
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "max_connections"
    value = "100"
  }

  parameter {
    name  = "log_min_duration_statement"
    value = "1000"
  }
}

# Provision the RDS PostgreSQL Instance
resource "aws_db_instance" "postgres_db" {
  identifier             = var.db_identifier
  engine                 = "postgres"
  engine_version         = var.engine_version
  instance_class         = var.instance_class
  allocated_storage      = var.storage_size
  storage_type           = "gp2"
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_kms_key.arn
  db_name                = var.db_name
  username               = var.db_username
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  parameter_group_name   = aws_db_parameter_group.postgres_parameter_group.name
  multi_az               = true
  publicly_accessible    = false
  skip_final_snapshot    = true
  backup_retention_period = 7

  tags = {
    Name = "Secure-PostgreSQL-Instance"
  }
}

# Variable definitions for user input
variable "aws_region" {
  description = "AWS region where resources will be created"
  default     = "us-east-1"
}

variable "vpc_id" {
  description = "The VPC ID where the database will be deployed"
}

variable "private_subnet_ids" {
  description = "List of private subnet IDs for the DB Subnet Group"
  type        = list(string)
}

variable "allowed_cidr_blocks" {
  description = "List of CIDR blocks allowed to access the database"
  type        = list(string)
  default     = ["10.0.0.0/16"]
}

variable "db_identifier" {
  description = "Identifier for the DB instance"
  default     = "secure-postgres-db"
}

variable "db_name" {
  description = "The name of the database to create"
  default     = "myappdb"
}

variable "db_username" {
  description = "Master username for the database"
  default     = "dbadmin"
}

variable "engine_version" {
  description = "PostgreSQL engine version"
  default     = "14.7"
}

variable "instance_class" {
  description = "Instance class for the database"
  default     = "db.t3.medium"
}

variable "storage_size" {
  description = "Storage size in GB"
  default     = 20
}

# Output the DB Endpoint and generated password
output "db_endpoint" {
  description = "The endpoint of the database"
  value       = aws_db_instance.postgres_db.endpoint
}

output "db_password" {
  description = "The generated password for the database"
  value       = random_password.db_password.result
  sensitive   = true
}

