resource "aws_kms_alias" "rds_kms_alias" {
  name          = "alias/rds-postgres-key"
  target_key_id = aws_kms_key.rds_encryption_key.key_id
}

# Resource: Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds-postgres-sg"
  description = "Security group for PostgreSQL database"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL access from allowed CIDRs"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgres-sg"
  }
}

# Resource: DB Subnet Group
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-postgres-subnet-group"
  subnet_ids = var.private_subnet_ids

  tags = {
    Name = "rds-postgres-subnet-group"
  }
}

# Resource: DB Parameter Group
resource "aws_db_parameter_group" "rds_pg15_parameter_group" {
  name        = "rds-pg15-custom-params"
  family      = "postgres15"
  description = "Custom parameter group for PostgreSQL 15"

  # Example parameters (adjust as needed)
  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "max_connections"
    value = "100"
  }
}

# Resource: RDS Instance
resource "aws_db_instance" "postgres_db" {
  identifier             = "secure-postgres-db"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.medium"
  allocated_storage      = 50
  storage_type           = "gp2"
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_encryption_key.arn
  multi_az               = true

  username               = var.db_credentials.username
  password               = var.db_credentials.password

  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  parameter_group_name   = aws_db_parameter_group.rds_pg15_parameter_group.name

  publicly_accessible    = false
  skip_final_snapshot    = true
  deletion_protection    = false # Set to true in production

  backup_retention_period = 7
  maintenance_window      = "Mon:03:00-Mon:04:00"

  tags = {
    Name        = "secure-postgres-db"
    Environment = "production"
  }
}

