}

data "aws_caller_identity" "current" {}

data "aws_availability_zones" "available" {
  state = "available"
}

# VPC Configuration
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "secure-postgres-vpc"
  }
}

# Subnets (Private)
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "postgres-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "postgres-subnet-2"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "My PostgreSQL Subnet Group"
  }
}

# Security Group
resource "aws_vpc_security_group" "db_sg" {
  name        = "postgres-security-group"
  description = "Security group for PostgreSQL database"
  vpc_id      = aws_vpc.main.id

  tags = {
    Name = "postgres-security-group"
  }
}

resource "aws_vpc_security_group_ingress_rule" "allow_postgres" {
  security_group_id = aws_vpc_security_group.db_sg.id
  cidr_ipv4         = aws_vpc.main.cidr_block
  from_port         = 5432
  ip_protocol       = "tcp"
  to_port           = 5432
}

resource "aws_vpc_security_group_egress_rule" "allow_all_traffic" {
  security_group_id = aws_vpc_security_group.db_sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

# KMS Key for Encryption
resource "aws_kms_key" "rds_encryption" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow RDS to use the key"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })

  tags = {
    Name = "rds-postgres-key"
  }
}

resource "aws_kms_alias" "rds_alias" {
  name          = "alias/rds-postgres-key"
  target_key_id = aws_kms_key.rds_encryption.key_id
}

# Random Password Generator
resource "random_password" "db_password" {
  length  = 16
  special = true
}

# DB Parameter Group
resource "aws_db_parameter_group" "postgres_pg" {
  name        = "custom-postgres-pg"
  family      = "postgres15"
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "max_connections"
    value = "100"
  }
}

# RDS Instance
resource "aws_db_instance" "postgres" {
  identifier             = "secure-postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_encryption.arn
  db_name                = "mypostgresdb"
  username               = "dbadmin"
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_vpc_security_group.db_sg.id]
  parameter_group_name   = aws_db_parameter_group.postgres_pg.name
  multi_az               = true
  backup_retention_period = 7
  skip_final_snapshot    = true
  publicly_accessible    = false

  tags = {
    Name = "SecurePostgreSQLInstance"
  }
}

