variable "db_password" {
  description = "Master password for the database"
  type        = string
  sensitive   = true
}

variable "allowed_cidr_blocks" {
  description = "List of CIDR blocks allowed to access the database"
  type        = list(string)
  default     = ["10.0.0.0/16"]
}

# Resource: KMS Key for encryption
resource "aws_kms_key" "rds_encryption_key" {
  description             = "KMS key for encrypting the PostgreSQL RDS instance"
  deletion_window_in_days = 10
  enable_key_rotation     = true
  tags = {
    Name = "rds-postgres-kms-key"
  }
}

resource "aws_kms_alias" "rds_encryption_key_alias" {
  name          = "alias/rds-postgres-key"
  target_key_id = aws_kms_key.rds_encryption_key.key_id
}

# Resource: Custom Parameter Group for PostgreSQL
resource "aws_db_parameter_group" "postgres_parameter_group" {
  name        = "custom-postgres-pg"
  family      = "postgres14"
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_statement"
    value = "ddl"
  }
}

# Resource: Security Group to manage access
resource "aws_security_group" "rds_security_group" {
  name_prefix = "postgres-rds-sg-"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL access from allowed CIDRs"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    description = "Allow all outbound traffic"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-rds-sg"
  }
}

# Resource: DB Subnet Group
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = var.subnet_ids
  description = "Subnet group for PostgreSQL RDS instance"

  tags = {
    Name = "postgres-subnet-group"
  }
}

# Resource: RDS PostgreSQL Instance
resource "aws_db_instance" "postgres_db" {
  identifier             = "secure-postgres-instance"
  engine                 = "postgres"
  engine_version         = var.db_engine_version
  instance_class         = var.db_instance_class
  allocated_storage      = var.db_allocated_storage
  storage_type           = "gp2"
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_encryption_key.arn

  # Authentication
  db_name                = "mydb"
  username               = var.db_username
  password               = var.db_password

  # Network
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_security_group.id]
  publicly_accessible    = false
  multi_az               = true

  # Configuration
  parameter_group_name   = aws_db_parameter_group.postgres_parameter_group.name

  # Maintenance and Backups
  backup_retention_period = 7
  backup_window          = "03:00-04:00"
  maintenance_window     = "Mon:04:00-Mon:05:00"
  skip_final_snapshot    = false
  final_snapshot_identifier = "pgsnapshot"

  # Deletion protection (Recommended for production)
  deletion_protection = false

  tags = {
    Name        = "Secure-PostgreSQL"
    Environment = "Production"
  }
}

