terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC and Networking Configuration to support Public Subnets
resource "aws_vpc" "airbyte_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "airbyte-test-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.airbyte_vpc.id

  tags = {
    Name = "airbyte-igw"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.airbyte_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "airbyte-public-rt"
  }
}

# Define Public Subnets
resource "aws_subnet" "public_subnet_1" {
  vpc_id                  = aws_vpc.airbyte_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-public-subnet-1"
  }
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id                  = aws_vpc.airbyte_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = data.aws_availability_zones.available.names[1]
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-public-subnet-2"
  }
}

resource "aws_route_table_association" "public_assoc_1" {
  subnet_id      = aws_subnet.public_subnet_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_assoc_2" {
  subnet_id      = aws_subnet.public_subnet_2.id
  route_table_id = aws_route_table.public_rt.id
}

# Data source for availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Security Group to allow PostgreSQL access
resource "aws_security_group" "rds_sg" {
  name        = "airbyte-rds-sg"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = aws_vpc.airbyte_vpc.id

  ingress {
    description = "PostgreSQL from anywhere"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-rds-sg"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "airbyte_subnet_group" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = [aws_subnet.public_subnet_1.id, aws_subnet.public_subnet_2.id]

  tags = {
    Name = "Airbyte Test DB Subnet Group"
  }
}

# Random Password Generator
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!%@"
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "airbyte_postgres" {
  identifier             = "airbyte-test-postgres"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp3"
  storage_encrypted      = false # Set to true for production encryption requirements

  db_name  = "airbyte_test"
  username = "airbyte_admin"
  password = random_password.db_password.result

  db_subnet_group_name   = aws_db_subnet_group.airbyte_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  publicly_accessible = true
  multi_az            = false # Set to true for high availability, false for cost saving in tests

  # Managed settings for low maintenance
  backup_retention_period = 1 # Keep low for testing
  backup_window          = "03:00-04:00"
  maintenance_window     = "Mon:04:00-Mon:05:00"

  auto_minor_version_upgrade = true
  deletion_protection        = false
  skip_final_snapshot        = true
  apply_immediately          = true

  tags = {
    Name        = "airbyte-postgres-15"
    Environment = "test"
  }
}

# Output the connection details
output "rds_endpoint" {
  description = "RDS PostgreSQL endpoint"
  value       = aws_db_instance.airbyte_postgres.endpoint
}

output "db_username" {
  description = "Database username"
  value       = aws_db_instance.airbyte_postgres.username
  sensitive   = true
}

output "db_password" {
  description = "Database password"
  value       = random_password.db_password.result
  sensitive   = true
}

