  type        = list(string)
  default     = ["0.0.0.0/0"]
}

# Resource: Random Password for the database
resource "random_password" "db_password" {
  length  = 32
  special = true
}

# Resource: Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name_prefix = "airbyte-rds-sg-"
  description = "Security Group for Airbyte PostgreSQL Test Instance"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL access from allowed CIDRs"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-test-rds-sg"
  }
}

# Resource: DB Subnet Group
# Groups the specific public subnets for the RDS instance
resource "aws_db_subnet_group" "airbyte_subnet_group" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = var.public_subnet_ids

  tags = {
    Name = "Airbyte Test Subnet Group"
  }
}

# Resource: RDS Instance (PostgreSQL 15)
resource "aws_db_instance" "airbyte_postgres" {
  identifier = "airbyte-test-postgres-15"

  engine         = "postgres"
  engine_version = "15.7"
  instance_class = "db.t3.medium"

  allocated_storage     = 500
  storage_type           = "gp3"
  storage_encrypted      = true
  max_allocated_storage  = 1000 # Allows storage to grow if needed

  db_name  = "airbyte_tests"
  username = "airbyte_admin"
  password = random_password.db_password.result

  db_subnet_group_name   = aws_db_subnet_group.airbyte_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  # Set to true as it is deployed in public subnets for connector testing
  publicly_accessible = true 

  # Managed settings for low maintenance
  parameter_group_name            = "default.postgres15"
  multi_az                        = false # Cost saving for test environment
  backup_retention_period         = 7
  skip_final_snapshot             = true # Avoids snapshot locks during destroy for tests
  delete_automated_backups        = true
  auto_minor_version_upgrade      = true
  apply_immediately               = true
  performance_insights_enabled    = true # Enhanced monitoring
  monitoring_interval             = 60
  deletion_protection             = false # Allow easy teardown

  tags = {
    Project = "AirbyteConnectorTests"
  }
}

# Outputs
output "db_endpoint" {
  description = "The connection endpoint for the PostgreSQL instance"
  value       = aws_db_instance.airbyte_postgres.endpoint
}

output "db_username" {
  description = "The master username"
  value       = aws_db_instance.airbyte_postgres.username
  sensitive   = true
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_db_subnet_group" "db-subnet-group" {
  name       = "db-subnet-group"
  subnet_ids = module.vpc.public_subnets
}

resource "aws_security_group" "db-sg" {
  name = "db-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  skip_final_snapshot             = true
  allocated_storage               = 500
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

