  default = true
}

# Retrieve subnets within the Default VPC
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Create a DB Subnet Group (Required for RDS)
resource "aws_db_subnet_group" "default" {
  name       = "mysql-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My MySQL Subnet Group"
  }
}

# Create a Security Group allowing public access on port 3306
resource "aws_security_group" "public_access_sg" {
  name        = "mysql-public-access-sg"
  description = "Allow inbound MySQL traffic from the world"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    description = "MySQL from the world"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-public-access-sg"
  }
}

# Create the MySQL RDS Instance
resource "aws_db_instance" "mysql" {
  identifier             = "my-mysql-instance"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  storage_encrypted      = false

  # Credentials
  db_name                = "mydatabase"
  username               = "admin"
  password               = random_password.db_password.result

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.public_access_sg.id]
  publicly_accessible    = true

  # Maintenance & Backups
  skip_final_snapshot    = true
  backup_retention_period = 0

  tags = {
    Name = "MyMySQLDatabase"
  }
}

