  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "aurora-subnet-private-${count.index}"
  }
}

data "aws_availability_zones" "available" {}

resource "aws_db_subnet_group" "main" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "Aurora Subnet Group"
  }
}

# ------------------------------------------------------------------------------
# Security Groups
# ------------------------------------------------------------------------------

# Security Group for RDS Cluster (Ingress from Proxy only)
resource "aws_security_group" "rds" {
  name        = "aurora-rds-sg"
  description = "Allow MySQL traffic from Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-rds-sg"
  }
}

# Security Group for RDS Proxy (Ingress from App/Client, Egress to RDS)
resource "aws_security_group" "proxy" {
  name        = "aurora-proxy-sg"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-proxy-sg"
  }
}

# ------------------------------------------------------------------------------
# Secrets Manager
# ------------------------------------------------------------------------------
resource "random_password" "password" {
  length  = 16
  special = true
}

resource "aws_secretsmanager_secret" "db" {
  name = "aurora-cluster-secret"
}

resource "aws_secretsmanager_secret_version" "db" {
  secret_id = aws_secretsmanager_secret.db.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.password.result
    engine   = "mysql"
    host     = aws_rds_cluster.main.endpoint
    port     = 3306
    dbClusterIdentifier = aws_rds_cluster.main.cluster_identifier
  })
}

# ------------------------------------------------------------------------------
# IAM Role for RDS Proxy
# ------------------------------------------------------------------------------
resource "aws_iam_role" "proxy" {
  name = "aurora-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "proxy_secrets" {
  role       = aws_iam_role.proxy.name
  policy_arn = "arn:aws:iam::aws:policy/SecretsManagerReadWrite" # Broad policy, can be scoped down
}

# ------------------------------------------------------------------------------
# RDS Aurora MySQL Cluster
# ------------------------------------------------------------------------------
resource "aws_rds_cluster" "main" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.02.0"
  database_name         = "mydb"
  master_username       = "admin"
  master_password       = random_password.password.result # Direct password, though Proxy uses Secret
  db_subnet_group_name  = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]

  skip_final_snapshot = true
  storage_encrypted   = true

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

resource "aws_rds_cluster_instance" "main" {
  count              = 1
  identifier         = "aurora-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.main.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.main.engine
  engine_version     = aws_rds_cluster.main.engine_version
  publicly_accessible = false
}

# ------------------------------------------------------------------------------
# RDS Proxy
# ------------------------------------------------------------------------------
resource "aws_db_proxy" "main" {
  name                   = "aurora-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = aws_subnet.private[*].id
  vpc_security_group_ids = [aws_security_group.proxy.id]
  role_arn               = aws_iam_role.proxy.arn
  auth {
    auth_scheme = "SECRETS"
    description = "Authentication via Secrets Manager"
    iam_auth    = "DISABLED"
    secret_arn  = aws_secretsmanager_secret.db.arn
  }
  depends_on = [aws_rds_cluster_instance.main]
}

resource "aws_db_proxy_default_target_group" "main" {
  db_proxy_name = aws_db_proxy.main.name
}

resource "aws_db_proxy_target" "main" {
  db_cluster_identifier = aws_rds_cluster.main.id
  db_proxy_name         = aws_db_proxy.main.name
  target_group_name     = "default"
}

