```hcl
provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the database
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!@"
}

# VPC Configuration
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "aurora-vpc"
  }
}

# Private Subnets for RDS
resource "aws_subnet" "private" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-${count.index + 1}"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "aurora" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "aurora-subnet-group"
  }
}

# Security Group for RDS Cluster
resource "aws_security_group" "rds" {
  name        = "aurora-rds-sg"
  description = "Security group for Aurora RDS cluster"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-rds-sg"
  }
}

# Security Group for RDS Proxy
resource "aws_security_group" "proxy" {
  name        = "aurora-proxy-sg"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-proxy-sg"
  }
}

# Secrets Manager Secret
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-db-credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# IAM Role for RDS Proxy
resource "aws_iam_role" "proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Secrets Manager Access
resource "aws_iam_role_policy" "proxy_secret_policy" {
  name = "proxy-secret-policy"
  role = aws_iam_role.proxy_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Resource = aws_secretsmanager_secret.db_credentials.arn
      }
    ]
  })
}

# Aurora MySQL Cluster
resource "aws_rds_cluster" "aurora" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.02.0"
  database_name         = "mydb"
  master_username       = "admin"
  master_password       = random_password.db_password.result
  db_subnet_group_name  = aws_db_subnet_group.aurora.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  skip_final_snapshot   = true

  # Ensure the cluster is created before the proxy attempts to register targets
  depends_on = [aws_iam_role_policy.proxy_secret_policy]
}

# Aurora Cluster Instance
resource "aws_rds_cluster_instance" "aurora" {
  engine               = aws_rds_cluster.aurora.engine
  engine_version       = aws_rds_cluster.aurora.engine_version
  identifier           = "aurora-instance-1"
  cluster_identifier   = aws_rds_cluster.aurora.id
  instance_class       = "db.t3.small"
  db_subnet_group_name = aws_db_subnet_group.aurora.name
  publicly_accessible  = false
}

# RDS Proxy
resource "aws_db_proxy" "proxy" {
  name                   = "aurora-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = aws_subnet.private[*].id
  role_arn               = aws_iam_role.proxy_role.arn
  vpc_security_group_ids = [aws_security_group.proxy.id]
  require_tls            = false

  auth {
    secret_arn = aws_secretsmanager_secret.db_credentials.arn
    iam_auth    = "DISABLED"
  }

  idle_client_timeout = 1800
  debug_logging       = false

  depends_on = [aws_rds_cluster_instance.aurora]
}

# RDS Proxy Default Target Group
resource "aws_db_proxy_default_target_group" "default" {
  db_proxy_name = aws_db_proxy.proxy.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent      = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = []
  }
}

# Register RDS Cluster with Proxy
resource "aws_db_proxy_target" "proxy_target" {
  db_proxy_name          = aws_db_proxy.proxy.name
  target_group_name      = aws_db_proxy_default_target_group.default.name
  db_instance_identifier = aws_rds_cluster_instance.aurora.identifier
  db_cluster_identifier  = aws_rds_cluster.aurora.id
}
