  db_subnet_group_name  = aws_db_subnet_group.aurora.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  skip_final_snapshot    = true
  apply_immediately      = true

  # Using the secret for authentication allows the proxy to retrieve credentials
  # Note: We still pass master_password for initial creation if not restored from snapshot, 
  # but referencing the secret is best practice for rotation.
