terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a secure password for the database
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!@"
}

# Create the AWS Lightsail MySQL Database
resource "aws_lightsail_database" "mysql_db" {
  relational_database_name = "my-mysql-db"
  engine                   = "mysql"
  engine_version           = "8.0"
  bundle_id                = "micro_2_0"
  master_database_name     = "myappdb"
  master_username          = "admin"
  master_password          = random_password.db_password.result
  availability_zone        = "us-east-1a"

  # Optional: Set to true to make the database accessible from the internet
  publicly_accessible      = true

  tags = {
    Name = "lightsail-mysql"
  }
}

# Create the AWS Lightsail Instance
resource "aws_lightsail_instance" "app_instance" {
  name              = "my-app-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  # Optional: Add user data to install MySQL client to connect to the DB
  user_data = <<-EOF
              #!/bin/bash
              sudo yum update -y
              sudo yum install mysql -y
              EOF

  tags = {
    Name = "lightsail-app-instance"
  }
}

output "db_endpoint" {
  description = "The master endpoint for the database"
  value       = aws_lightsail_database.mysql_db.master_endpoint_address
}

output "db_password" {
  description = "The database master password (sensitive)"
  value       = random_password.db_password.result
  sensitive   = true
}

