terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the Lightsail Bucket to act as the origin
resource "aws_lightsail_bucket" "origin" {
  name      = "my-lightsail-origin-bucket"
  bundle_id = "small_1_0"

  tags = {
    Name = "OriginBucket"
  }
}

# 2. Create a Certificate for the Distribution
# Note: Lightsail certificates require domain validation (DNS or Email) 
# which must be completed manually after creation.
resource "aws_lightsail_certificate" "dist_cert" {
  name        = "my-distribution-certificate"
  domain_name = "example.com"
  subject_alternative_names = [
    "www.example.com"
  ]
}

# 3. Create the Lightsail Distribution
resource "aws_lightsail_distribution" "cdn" {
  name             = "my-lightsail-distribution"
  bundle_id        = "small_1_0"
  certificate_name = aws_lightsail_certificate.dist_cert.name
  is_enabled       = true

  # Configuration for the Bucket Origin
  origin {
    name            = aws_lightsail_bucket.origin.name
    region_name     = "us-east-1"
    resource_type   = "L lightsailBucket"
    protocol_policy = "allow-all"
  }

  # Default Cache Behavior
  default_cache_behavior {
    behavior = "cache"
  }

  # Cache Settings
  cache_behavior_settings {
    allowed_http_methods = ["GET", "HEAD", "OPTIONS"]
    cached_http_methods  = ["GET", "HEAD"]
    default_ttl          = 86400
    maximum_ttl          = 31536000
    minimum_ttl          = 1

    forwarded_cookies {
      option = "none"
    }

    forwarded_headers {
      option = "none"
    }

    forwarded_query_strings {
      option = false
    }
  }
}

# 4. Grant the Distribution permission to access the Bucket
resource "aws_lightsail_bucket_resource_access" "access" {
  bucket_name   = aws_lightsail_bucket.origin.name
  resource_name = aws_lightsail_distribution.cdn.name
}

