}

provider "aws" {
  region = var.aws_region
}

variable "bucket_name" {
  description = "The name of the S3 bucket for long-term storage"
  type        = string
}

variable "aws_region" {
  description = "The AWS region where the bucket will be created"
  type        = string
  default     = "us-east-1"
}

# Create the S3 Bucket
resource "aws_s3_bucket" "storage_bucket" {
  bucket = var.bucket_name

  tags = {
    Name        = "Long-Term-Storage-Bucket"
    Environment = "Backup"
  }
}

# Enable Bucket Versioning for backup integrity
resource "aws_s3_bucket_versioning" "versioning" {
  bucket = aws_s3_bucket.storage_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Configure Server-Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "encryption" {
  bucket = aws_s3_bucket.storage_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Block Public Access to ensure data security
resource "aws_s3_bucket_public_access_block" "public_access_block" {
  bucket = aws_s3_bucket.storage_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Configure Lifecycle Rules to move data to cheaper storage tiers
resource "aws_s3_bucket_lifecycle_configuration" "lifecycle_rule" {
  bucket = aws_s3_bucket.storage_bucket.id

  rule {
    id     = "long_term_retention_rule"
    status = "Enabled"

    # Transition to Standard Infrequent Access after 30 days
    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    # Transition to Glacier Flexible Retrieval after 90 days
    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    # Transition to Glacier Deep Archive after 180 days (for very long term)
    transition {
      days          = 180
      storage_class = "DEEP_ARCHIVE"
    }

    # Optional: Expire objects after 10 years (remove if infinite retention is needed)
    # expiration {
    #   days = 3650
    # }
  }
}

