extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Note: AWS Data Lifecycle Manager (DLM) is specific to EBS snapshots and AMIs. 
# For S3 Glacier, S3 Lifecycle Configuration is the standard mechanism to automate data transitions.
# This configuration creates an S3 Bucket acting as a "Vault" with lifecycle rules to transition data to Glacier.

resource "aws_s3_bucket" "glacier_vault" {
  bucket_prefix = "glacier-vault-"
}

resource "aws_s3_bucket_versioning" "glacier_vault" {
  bucket = aws_s3_bucket.glacier_vault.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "glacier_lifecycle" {
  bucket = aws_s3_bucket.glacier_vault.id

  rule {
    id     = "glacier-transition-rule"
    status = "Enabled"

    # Transition current object versions to S3 Glacier Flexible Retrieval after 30 days
    transition {
      days          = 30
      storage_class = "GLACIER"
    }

    # Transition current object versions to S3 Glacier Deep Archive after 90 days
    transition {
      days          = 90
      storage_class = "DEEP_ARCHIVE"
    }

    # Transition non-current object versions to Glacier Flexible Retrieval after 30 days
    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class    = "GLACIER"
    }

    # Permanently delete non-current versions after 180 days
    noncurrent_version_expiration {
      noncurrent_days = 180
    }

    # Permanently delete expired object delete markers
    expiration {
      expired_object_delete_marker = true
    }
  }
}

reference:
resource "aws_glacier_vault" "example" {
  name = "my-glacier-vault"
}

resource "aws_dlm_lifecycle_policy" "example" {
  description = "Automated archiving policy"

  execution_role_arn = "arn:aws:iam::123456789012:role/DLMServiceRole"  # Replace with your DLM execution role ARN

  policy_details {
    resource_types = ["VOLUME"]
    target_tags = {
      "archive" = "true"
    }
    schedule {
      name = "2 weeks of daily snapshots"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["23:45"]
      }

      retain_rule {
        count = 14
      }

      tags_to_add = {
        SnapshotCreator = "DLM"
      }

      copy_tags = false
    }
  }
}

