terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Variable for VPC ID
variable "vpc_id" {
  description = "The ID of the VPC in which the NLB will be created"
  type        = string
}

# Variable for Subnet IDs
variable "subnet_ids" {
  description = "A list of subnet IDs to attach to the Network Load Balancer"
  type        = list(string)
}

# Create the Network Load Balancer (NLB)
resource "aws_lb" "network_load_balancer" {
  name               = "my-network-lb"
  internal           = false # Set to true for an internal NLB
  load_balancer_type = "network"
  subnets            = var.subnet_ids

  enable_deletion_protection = false
  enable_cross_zone_load_balancing = true

  tags = {
    Environment = "production"
  }
}

# Create a Target Group for the NLB
resource "aws_lb_target_group" "target_group" {
  name        = "my-nlb-tg"
  port        = 80
  protocol    = "TCP"
  vpc_id      = var.vpc_id
  target_type = "instance"

  health_check {
    enabled             = true
    healthy_threshold   = 3
    unhealthy_threshold = 3
    interval            = 30
    protocol            = "TCP"
    port                = 80
  }
}

# Create a Listener for the NLB
resource "aws_lb_listener" "frontend" {
  load_balancer_arn = aws_lb.network_load_balancer.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb.target_group.arn
  }
}

# Output the DNS name of the NLB
output "nlb_dns_name" {
  description = "DNS name of the load balancer"
  value       = aws_lb.network_load_balancer.dns_name
}
