  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# Network Load Balancer (NLB) - Internal
resource "aws_lb" "nlb" {
  name               = "internal-nlb"
  internal           = true
  load_balancer_type = "network"
  subnets            = aws_subnet.private[*].id

  enable_deletion_protection = false

  tags = {
    Environment = "production"
  }
}

# Target Group for NLB (e.g., pointing to EC2 instances)
resource "aws_lb_target_group" "nlb_tg" {
  name        = "nlb-tg"
  port        = 80
  protocol    = "TCP"
  vpc_id      = aws_vpc.main.id
  target_type = "instance"

  health_check {
    port = 80
  }
}

# NLB Listener
resource "aws_lb_listener" "nlb_listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = 80
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }
}

# Application Load Balancer (ALB) - Internet Facing
resource "aws_lb" "alb" {
  name               = "public-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public[*].id

  enable_deletion_protection = false

  tags = {
    Environment = "production"
  }
}

# Security Group for ALB
resource "aws_security_group" "alb_sg" {
  name        = "alb-sg"
  description = "Allow HTTP inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "HTTP from Internet"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Target Group for ALB (Forwarding to NLB)
# We use IP target type to forward to the NLB's private IPs
resource "aws_lb_target_group" "alb_tg" {
  name        = "alb-to-nlb-tg"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = aws_vpc.main.id
  target_type = "ip"

  health_check {
    path = "/"
  }
}

# Data source to retrieve NLB's Network Interfaces to get IPs
data "aws_network_interfaces" "nlb_enis" {
  depends_on = [aws_lb.nlb]

  filter {
    name   = "description"
    values = ["ELB ${aws_lb.nlb.arn_suffix}"] # Note: ARN suffix matching or description matching can be tricky, this is a simplified filter.
  }
}

# Attach NLB IPs to ALB Target Group
resource "aws_lb_target_group_attachment" "alb_to_nlb" {
  count             = 2 # Assuming 2 subnets/NLB IPs
  target_group_arn  = aws_lb_target_group.alb_tg.arn
  target_id         = data.aws_network_interfaces.nlb_enis.ids[count.index] # This binds the ENI ID. In ALB IP target type, you need the Private IP, but Terraform aws_lb_target_group_attachment accepts ID. 
  # Correction: aws_lb_target_group_attachment for target_type "ip" requires the actual IP address string, not the ENI ID.
  # Getting the IP address requires data "aws_network_interface".
  port              = 80
}

# ALB Listener forwarding to NLB
resource "aws_lb_listener" "alb_listener" {
  load_balancer_arn = aws_lb.alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.alb_tg.arn
  }
}

