terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Data source for Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# --- VPC and Networking ---
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "alb-vpc"
  }
}

resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "alb-subnet-${count.index}"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "alb-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "alb-public-rt"
  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# --- Security Group ---
resource "aws_security_group" "lb_sg" {
  name        = "lb-sg"
  description = "Security group for Load Balancer"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "HTTP from anywhere"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "lb-sg"
  }
}

# --- Cognito User Pool ---
resource "aws_cognito_user_pool" "pool" {
  name = "auth-pool"

  password_policy {
    minimum_length    = 8
    require_lowercase = true
    require_numbers   = true
    require_symbols   = true
    require_uppercase = true
  }

  tags = {
    Name = "auth-pool"
  }
}

resource "aws_cognito_user_pool_client" "client" {
  name         = "auth-client"
  user_pool_id = aws_cognito_user_pool.pool.id

  # Prevent user existence errors is often required for ALB auth flows
  prevent_user_existence_errors = "ENABLED"

  # Note: In production, callback URLs should match the Load Balancer DNS name.
  # Since the LB DNS name is not known until creation, we use a placeholder here
  # to allow the configuration to apply. You should update this with the actual 
  # LB DNS name (e.g., "http://my-lb-1234567890.us-east-1.elb.amazonaws.com/oauth2/callback")
  callback_urls                = ["https://example.com/callback"]
  logout_urls                  = ["https://example.com/signout"]
  allowed_oauth_flows         = ["code"]
  allowed_oauth_scopes        = ["email", "openid"]
  supported_identity_providers = ["COGNITO"]
}

resource "aws_cognito_user_pool_domain" "domain" {
  domain       = "my-auth-domain-unique-id-123" # Must be globally unique
  user_pool_id = aws_cognito_user_pool.pool.id
}

# --- Load Balancer Resources ---
resource "aws_lb" "front_end" {
  name               = "alb-with-cognito"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = aws_subnet.public[*].id

  tags = {
    Name = "alb-with-cognito"
  }
}

resource "aws_lb_target_group" "back_end" {
  name     = "tg-back-end"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  health_check {
    path = "/"
  }
}

# --- Listener with authenticate-cognito Action ---
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.front_end.arn
  port              = "80"
  protocol          = "HTTP"

  # Action 1: Authenticate with Cognito
  default_action {
    type = "authenticate-cognito"

    authenticate_cognito {
      user_pool_arn       = aws_cognito_user_pool.pool.arn
      user_pool_client_id = aws_cognito_user_pool_client.client.id
      user_pool_domain    = aws_cognito_user_pool_domain.domain.domain

      # Session cookie settings
      session_cookie_name   = "AWSELBAuthSessionCookie"
      session_timeout       = 604800
      scope                 = "email openid"
      on_unauthenticated_request = "authenticate"
    }
  }

  # Action 2: Forward to Target Group (Chained after auth)
  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.back_end.arn
  }
}
