provider "aws" {
  region = "us-east-1"
}

# VPC and Networking Setup
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
}

resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
}

# Security Group for Load Balancer
resource "aws_security_group" "lb_sg" {
  name        = "lb-security-group"
  description = "Allow HTTP/HTTPS inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "HTTPS from Internet"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Target Group
resource "aws_lb_target_group" "main" {
  name     = "tg-oidc-example"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
}

# Application Load Balancer
resource "aws_lb" "main" {
  name               = "lb-oidc-example"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = aws_subnet.public[*].id
}

# Listener (Port 443)
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.main.arn
  port              = "443"
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"

  # Note: In a real scenario, use a valid certificate ARN
  certificate_arn   = "arn:aws:iam::123456789012:server-certificate/test_cert"

  default_action {
    type = "fixed-response"
    fixed_response {
      content_type = "text/plain"
      message_body = "Authentication Failed or No Route Matched"
      status_code  = "403"
    }
  }
}

# Variables for OIDC Configuration
variable "oidc_client_id" {
  description = "The client ID for the OIDC identity provider"
  type        = string
  default     = "example-client-id"
}

variable "oidc_client_secret" {
  description = "The client secret for the OIDC identity provider"
  type        = string
  sensitive   = true
}

variable "oidc_issuer" {
  description = "The OIDC issuer URL"
  type        = string
  default     = "https://accounts.example.com"
}

variable "oidc_authorization_endpoint" {
  description = "The authorization endpoint of the IdP"
  type        = string
  default     = "https://accounts.example.com/oauth2/authorize"
}

variable "oidc_token_endpoint" {
  description = "The token endpoint of the IdP"
  type        = string
  default     = "https://accounts.example.com/oauth2/token"
}

variable "oidc_user_info_endpoint" {
  description = "The user info endpoint of the IdP"
  type        = string
  default     = "https://accounts.example.com/oauth2/userinfo"
}

# Listener Rule with Authenticate-OIDC Action
resource "aws_lb_listener_rule" "oidc_rule" {
  listener_arn = aws_lb_listener.front_end.arn
  priority     = 100

  action {
    type             = "authenticate-oidc"
    authenticate_oidc {
      authorization_endpoint = var.oidc_authorization_endpoint
      client_id              = var.oidc_client_id
      client_secret          = var.oidc_client_secret
      issuer                 = var.oidc_issuer
      token_endpoint         = var.oidc_token_endpoint
      user_info_endpoint     = var.oidc_user_info_endpoint

      # Optional: Define what happens if authentication fails
      on_unauthenticated_request = "authenticate"
    }
  }

  action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.main.arn
  }

  condition {
    path_pattern {
      values = ["/secure/*"]
    }
  }
}

