provider "aws" {
  region = "us-east-1"
}

variable "snapshot_identifier" {
  description = "The identifier or ARN of the snapshot to restore from"
  type        = string
}

variable "instance_class" {
  description = "The instance type of the database"
  default     = "db.t3.micro"
  type        = string
}

variable "db_identifier" {
  description = "The identifier for the restored database instance"
  default     = "restored-database"
  type        = string
}

resource "aws_db_instance" "restored_db" {
  identifier          = var.db_identifier
  instance_class      = var.instance_class

  # Restores the database from the specified snapshot
  snapshot_identifier = var.snapshot_identifier

  # Allocated storage must be equal to or greater than the snapshot's storage
  allocated_storage   = 20 
  storage_type        = "gp2"

  # Engine must match the engine of the snapshot
  engine              = "mysql" 

  # Username and password are inherited from the snapshot, do not set them here

  publicly_accessible = false
  skip_final_snapshot = true

  tags = {
    Name        = var.db_identifier
    Environment = "restored"
  }
}

