    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS Instance with Managed Master Password
resource "aws_db_instance" "this" {
  identifier = "managed-password-db"

  # Engine settings
  engine         = "postgres"
  engine_version = "14.7"
  instance_class = "db.t3.micro"
  allocated_storage = 20
  storage_type      = "gp2"

  # Credentials
