provider "aws" {
  region = "us-east-1"
}

# Security Group to allow NFS traffic
resource "aws_security_group" "efs_sg" {
  name        = "efs-security-group"
  description = "Allow NFS inbound traffic"
  vpc_id      = var.vpc_id

  ingress {
    description = "NFS from VPC"
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = [var.vpc_cidr]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "efs-sg"
  }
}

# EFS File System
resource "aws_efs_file_system" "this" {
  creation_token = "my-efs"
  encrypted      = true

  tags = {
    Name = "MyEFS"
  }
}

# EFS Lifecycle Policy
# Moves files into Infrequent Access (IA) storage class after 30 days
resource "aws_efs_lifecycle_policy" "this" {
  file_system_id = aws_efs_file_system.this.id

  transition_to_ia = "AFTER_30_DAYS"
}

# Mount Target (Required to access the EFS from a subnet)
resource "aws_efs_mount_target" "this" {
  file_system_id  = aws_efs_file_system.this.id
  subnet_id       = var.subnet_id
  security_groups = [aws_security_group.efs_sg.id]
}

# Variables
variable "vpc_id" {
  description = "The ID of the VPC where EFS will be created"
  type        = string
}

variable "subnet_id" {
  description = "The ID of the subnet where the mount target will be created"
  type        = string
}

variable "vpc_cidr" {
  description = "CIDR block of the VPC to allow NFS traffic"
  type        = string
  default     = "10.0.0.0/16"
