terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create the EFS File System
resource "aws_efs_file_system" "this" {
  creation_token = "terraform-efs-example"
  encrypted      = true

  # Lifecycle Policy to transition files to Infrequent Access (IA) storage
  lifecycle_policy {
    transition_to_ia = "AFTER_30_DAYS"
  }

  tags = {
    Name = "TerraformEFS"
  }
}

# Define the File System Policy (System Policy)
# This controls who has access to the EFS file system
resource "aws_efs_file_system_policy" "this" {
  file_system_id = aws_efs_file_system.this.id

  # This policy allows the root user of the connecting EC2 instance full access
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid     = "ExampleStatement"
        Effect  = "Allow"
        Principal = {
          AWS = "*"
        }
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite"
        ]
        Resource = "${aws_efs_file_system.this.arn}"
        Condition = {
          Bool = {
            "elasticfilesystem:AccessedViaMountTarget" = "true"
          }
        }
      }
    ]
  })
}

# Backup Policy (Optional but recommended for a complete system configuration)
resource "aws_efs_backup_policy" "this" {
  file_system_id = aws_efs_file_system.this.id

  backup_policy {
    status = "ENABLED"
  }
}

# Create Mount Targets (Required for EFS to be accessible in a VPC)
# Note: You typically need one mount target per Availability Zone used
resource "aws_efs_mount_target" "this" {
  count           = length(var.subnet_ids)
  file_system_id  = aws_efs_file_system.this.id
  subnet_id       = var.subnet_ids[count.index]
  security_groups = var.security_group_ids
}

