}

# Variables to define VPC and Subnet configuration
variable "vpc_id" {
  description = "The ID of the VPC where the EFS will be created"
  type        = string
  default     = "" # Replace with your VPC ID
}

variable "subnet_ids" {
  description = "A list of subnet IDs where mount targets will be created"
